//! The single error type for tb-vmm.
//!
//! Maturity requirement: there is **no `unwrap` on the boot path**. Every
//! fallible step returns [`VmmError`], which carries enough context to diagnose
//! a boot failure (and, for guest faults, the KVM exit reason).

use std::fmt;
use std::path::PathBuf;

use crate::device::BusError;
use crate::loader::LoaderError;

/// All the ways a tb-vmm run can fail.
#[derive(Debug)]
pub enum VmmError {
    /// `/dev/kvm` could not be opened (absent, or no read+write permission).
    KvmInit(kvm_ioctls::Error),
    /// A KVM ioctl failed.
    Kvm(kvm_ioctls::Error),
    /// `KVM_API_VERSION` mismatch (KVM is unusably old/new).
    ApiVersion(i32),
    /// Allocating guest RAM (the anonymous mmap) failed.
    GuestMemoryCreate(String),
    /// A read/write against guest RAM failed (out of range, etc.).
    MemoryAccess(vm_memory::GuestMemoryError),
    /// The kernel image file could not be read.
    KernelRead(PathBuf, std::io::Error),
    /// The kernel ELF could not be parsed/loaded.
    Loader(LoaderError),
    /// Registering a device on a bus failed (address overlap).
    Bus(BusError),
    /// A configuration value is invalid (e.g. cmdline too long for the boot window).
    Config(String),
    /// A feature is not implemented on the current host architecture.
    Unsupported(&'static str),
    /// The wall-clock run guard fired before the guest halted.
    Timeout {
        /// The configured guard, in seconds.
        secs: u64,
    },
    /// The VM-exit budget was exhausted (guard against a hung guest).
    ExitBudget(u64),
    /// `KVM_EXIT_FAIL_ENTRY`: the vCPU could not enter the guest.
    GuestFault {
        /// Hardware entry-failure reason word.
        reason: u64,
        /// The vCPU index reported by KVM.
        cpu: u32,
    },
    /// `KVM_EXIT_INTERNAL_ERROR`: KVM hit an internal/emulation error.
    InternalError,
}

impl fmt::Display for VmmError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            VmmError::KvmInit(e) => write!(
                f,
                "could not initialise KVM (open /dev/kvm): {e}. Ensure the host exposes \
                 /dev/kvm and the current user can read+write it (e.g. `sudo chmod 666 /dev/kvm`)"
            ),
            VmmError::Kvm(e) => write!(f, "KVM ioctl failed: {e}"),
            VmmError::ApiVersion(v) => {
                write!(f, "unexpected KVM_API_VERSION {v} (tb-vmm requires 12)")
            }
            VmmError::GuestMemoryCreate(e) => write!(f, "failed to allocate guest RAM: {e}"),
            VmmError::MemoryAccess(e) => write!(f, "guest memory access failed: {e}"),
            VmmError::KernelRead(path, e) => {
                write!(f, "could not read kernel image `{}`: {e}", path.display())
            }
            VmmError::Loader(e) => write!(f, "kernel ELF load failed: {e}"),
            VmmError::Bus(e) => write!(f, "device bus error: {e}"),
            VmmError::Config(msg) => write!(f, "invalid configuration: {msg}"),
            VmmError::Unsupported(msg) => write!(f, "unsupported: {msg}"),
            VmmError::Timeout { secs } => {
                write!(f, "guest did not halt within the {secs}s run guard")
            }
            VmmError::ExitBudget(n) => {
                write!(f, "VM-exit budget of {n} exhausted (guest appears hung)")
            }
            VmmError::GuestFault { reason, cpu } => write!(
                f,
                "KVM_EXIT_FAIL_ENTRY on vCPU {cpu}: hardware_entry_failure_reason={reason:#x}"
            ),
            VmmError::InternalError => write!(f, "KVM_EXIT_INTERNAL_ERROR"),
        }
    }
}

impl std::error::Error for VmmError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            VmmError::KvmInit(e) | VmmError::Kvm(e) => Some(e),
            VmmError::MemoryAccess(e) => Some(e),
            VmmError::KernelRead(_, e) => Some(e),
            VmmError::Loader(e) => Some(e),
            VmmError::Bus(e) => Some(e),
            _ => None,
        }
    }
}

impl From<kvm_ioctls::Error> for VmmError {
    fn from(e: kvm_ioctls::Error) -> Self {
        VmmError::Kvm(e)
    }
}

impl From<vm_memory::GuestMemoryError> for VmmError {
    fn from(e: vm_memory::GuestMemoryError) -> Self {
        VmmError::MemoryAccess(e)
    }
}

impl From<LoaderError> for VmmError {
    fn from(e: LoaderError) -> Self {
        VmmError::Loader(e)
    }
}

impl From<BusError> for VmmError {
    fn from(e: BusError) -> Self {
        VmmError::Bus(e)
    }
}

//! Guest RAM management: a `vm-memory` [`GuestMemoryMmap`] (anonymous mmap in
//! the VMM's address space) registered with KVM via `KVM_SET_USER_MEMORY_REGION`.
//!
//! This module owns tb-vmm's single intentional `unsafe` block — the FFI
//! handoff of the host mapping to the kernel. It is isolated and commented per
//! the SOVEREIGNTY-ROADMAP §3 rule that tb-vmm's `unsafe` stays small + audited.
//!
//! Sources:
//! * `KVM_SET_USER_MEMORY_REGION` / `kvm_userspace_memory_region`:
//!   <https://docs.kernel.org/virt/kvm/api.html>
//! * `VmFd::set_user_memory_region` (unsafe; "no guarantee userspace_addr points
//!   to a valid memory region, nor the memory region lives as long as the kernel
//!   needs it to"): docs.rs/kvm-ioctls `VmFd`.
//! * `GuestMemoryMmap::from_ranges`: docs.rs/vm-memory.

use kvm_bindings::kvm_userspace_memory_region;
use kvm_ioctls::VmFd;
use vm_memory::{Address, GuestAddress, GuestMemory, GuestMemoryMmap, GuestMemoryRegion};

use crate::error::VmmError;

/// Logical kind of a guest physical memory region, as reported to the guest in
/// the tb-boot [`tb_boot::TbMemRegion`] array (`kind`: Ram=1, Reserved=2).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
#[repr(u32)]
pub enum MemKind {
    /// Usable RAM.
    Ram = 1,
    /// Reserved (not usable by the guest allocator).
    Reserved = 2,
}

/// One contiguous guest physical memory region in the logical map handed to the
/// guest. (Distinct from the KVM memslot list, though for a single-region VM
/// they coincide.)
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MemRegion {
    /// Guest physical base address.
    pub base: u64,
    /// Length in bytes.
    pub len: u64,
    /// Region kind reported to the guest.
    pub kind: MemKind,
}

/// Guest RAM: the backing `GuestMemoryMmap` plus the logical region map.
pub struct GuestRam {
    inner: GuestMemoryMmap,
    regions: Vec<MemRegion>,
}

impl GuestRam {
    /// Allocate `size_bytes` of guest RAM as one contiguous region based at
    /// guest physical 0. The mapping is anonymous and zero-initialised, which
    /// satisfies the kernel's assumption that `.bss` / page-table frames start
    /// zeroed.
    pub fn new(size_bytes: u64) -> Result<Self, VmmError> {
        let size = usize::try_from(size_bytes)
            .map_err(|_| VmmError::Config("memory size too large for this host".into()))?;
        let inner = GuestMemoryMmap::from_ranges(&[(GuestAddress(0), size)])
            .map_err(|e| VmmError::GuestMemoryCreate(e.to_string()))?;
        let regions = vec![MemRegion {
            base: 0,
            len: size_bytes,
            kind: MemKind::Ram,
        }];
        Ok(Self { inner, regions })
    }

    /// The backing guest memory (for the loader + boot-structure writes).
    pub fn inner(&self) -> &GuestMemoryMmap {
        &self.inner
    }

    /// The logical region map reported to the guest via tb-boot.
    pub fn regions(&self) -> &[MemRegion] {
        &self.regions
    }

    /// Register every backing region with KVM as a userspace memory slot.
    ///
    /// Must be called once, after `create_vm` and before the first `KVM_RUN`.
    /// `self` must outlive the [`VmFd`]: the mappings stay valid only while this
    /// `GuestRam` is alive (enforced by [`crate::vmm::Vmm`] owning both).
    pub fn register_with_kvm(&self, vm: &VmFd) -> Result<(), VmmError> {
        for (slot, region) in self.inner.iter().enumerate() {
            let guest_phys_addr = region.start_addr().raw_value();
            let memory_size = region.len();
            // Host address of the region's base byte. For a `GuestMemoryMmap`
            // this is the mmap base, which is what KVM needs as userspace_addr.
            let host_addr = self.inner.get_host_address(region.start_addr())?;

            let mem_region = kvm_userspace_memory_region {
                slot: slot as u32,
                flags: 0,
                guest_phys_addr,
                memory_size,
                userspace_addr: host_addr as u64,
            };

            // SAFETY: `host_addr` is the base of a live anonymous mmap owned by
            // `self.inner`, of exactly `memory_size` bytes (vm-memory invariant).
            // `self` (and therefore the mapping) outlives `vm` because
            // `crate::vmm::Vmm` holds both and drops the VM fd first. The regions
            // come from a single non-overlapping `from_ranges` allocation, so the
            // "regions are not overlapping" precondition holds. This is the one
            // audited FFI handoff that places tb-vmm outside forbid(unsafe).
            unsafe {
                vm.set_user_memory_region(mem_region)?;
            }
        }
        Ok(())
    }
}

//! ELF64 kernel loader.
//!
//! A small, fully bounds-checked hand-rolled parser (chosen over `goblin` so the
//! parse surface is auditable + unit-testable with synthetic byte buffers, and
//! tb-vmm carries no `unsafe` here). It:
//!  1. copies every `PT_LOAD` segment to its `p_paddr` in guest RAM, zeroing the
//!     `p_memsz - p_filesz` `.bss` tail;
//!  2. locates the TABOS boot note (`PT_NOTE`, name `\"TABOS\"`,
//!     type [`tb_boot::TB_NOTE_TYPE_ENTRY64`]) whose 8-byte descriptor is the
//!     kernel's 64-bit `tb-boot` entry; falls back to `e_entry` if absent.
//!
//! Layout per the System V gABI / `elf.h` (`Elf64_Ehdr`/`Elf64_Phdr`/`Elf64_Nhdr`).
//! The TABOS note mirrors the Xen `PHYS32_ENTRY` note used by the PVH path
//! (crates/tb-hal/src/arch/x86_64/boot.rs).

use std::fmt;

use vm_memory::{Bytes, GuestAddress, GuestMemoryMmap};

// --- ELF constants (elf.h) -------------------------------------------------
const EI_NIDENT: usize = 16;
const ELFCLASS64: u8 = 2;
const ELFDATA2LSB: u8 = 1;
const EM_X86_64: u16 = 62;
const PT_LOAD: u32 = 1;
const PT_NOTE: u32 = 4;
const EHDR_SIZE: usize = 64;
const PHDR_SIZE: usize = 56;

/// The 64-bit entry discovered for the kernel + the highest loaded address.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct LoadedKernel {
    /// The guest physical address to set `rip` to (TABOS note, or `e_entry`).
    pub entry: u64,
    /// Whether [`Self::entry`] came from the TABOS note (`false` = `e_entry`).
    pub entry_from_note: bool,
    /// One past the highest `p_paddr + p_memsz` of any loaded segment.
    pub image_end: u64,
}

/// Errors from parsing/loading the kernel ELF.
#[derive(Debug, PartialEq, Eq)]
pub enum LoaderError {
    /// The buffer is too small to contain an ELF header / a referenced structure.
    Truncated(&'static str),
    /// Missing the `\x7fELF` magic.
    BadMagic,
    /// Not an ELFCLASS64 little-endian image.
    NotElf64Le,
    /// `e_machine` is not `EM_X86_64`.
    BadMachine(u16),
    /// A program header references bytes outside the file.
    SegmentOutOfFile {
        /// Segment index.
        index: usize,
    },
    /// `p_filesz > p_memsz` for a `PT_LOAD` segment.
    BadSegmentSize {
        /// Segment index.
        index: usize,
    },
    /// No `PT_LOAD` segments were present.
    NoLoadSegments,
    /// Writing a segment to guest RAM failed (segment out of guest range, etc.).
    GuestWrite {
        /// Guest physical destination address.
        paddr: u64,
        /// Underlying message.
        detail: String,
    },
}

impl fmt::Display for LoaderError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            LoaderError::Truncated(what) => write!(f, "ELF truncated: {what}"),
            LoaderError::BadMagic => write!(f, "not an ELF file (bad magic)"),
            LoaderError::NotElf64Le => write!(f, "not a 64-bit little-endian ELF"),
            LoaderError::BadMachine(m) => write!(f, "unexpected e_machine {m:#x} (want x86_64=62)"),
            LoaderError::SegmentOutOfFile { index } => {
                write!(f, "program header {index} references bytes past end of file")
            }
            LoaderError::BadSegmentSize { index } => {
                write!(f, "program header {index} has p_filesz > p_memsz")
            }
            LoaderError::NoLoadSegments => write!(f, "ELF has no PT_LOAD segments"),
            LoaderError::GuestWrite { paddr, detail } => {
                write!(f, "failed to write segment to guest paddr {paddr:#x}: {detail}")
            }
        }
    }
}

impl std::error::Error for LoaderError {}

// --- little-endian readers (bounds-checked) --------------------------------
fn rd_u16(b: &[u8], off: usize, what: &'static str) -> Result<u16, LoaderError> {
    let s = b.get(off..off + 2).ok_or(LoaderError::Truncated(what))?;
    Ok(u16::from_le_bytes([s[0], s[1]]))
}
fn rd_u32(b: &[u8], off: usize, what: &'static str) -> Result<u32, LoaderError> {
    let s = b.get(off..off + 4).ok_or(LoaderError::Truncated(what))?;
    Ok(u32::from_le_bytes([s[0], s[1], s[2], s[3]]))
}
fn rd_u64(b: &[u8], off: usize, what: &'static str) -> Result<u64, LoaderError> {
    let s = b.get(off..off + 8).ok_or(LoaderError::Truncated(what))?;
    Ok(u64::from_le_bytes([
        s[0], s[1], s[2], s[3], s[4], s[5], s[6], s[7],
    ]))
}

/// Round `n` up to the next multiple of 4 (ELF note field alignment).
fn align4(n: usize) -> usize {
    (n + 3) & !3
}

/// A parsed program header (only the fields we need).
#[derive(Clone, Copy, Debug)]
struct Phdr {
    p_type: u32,
    p_offset: u64,
    p_paddr: u64,
    p_filesz: u64,
    p_memsz: u64,
}

/// Parse the program-header table.
fn parse_phdrs(image: &[u8]) -> Result<Vec<Phdr>, LoaderError> {
    if image.len() < EHDR_SIZE {
        return Err(LoaderError::Truncated("ELF header"));
    }
    if &image[0..4] != b"\x7fELF" {
        return Err(LoaderError::BadMagic);
    }
    if image[4] != ELFCLASS64 || image[5] != ELFDATA2LSB {
        return Err(LoaderError::NotElf64Le);
    }
    let _ = EI_NIDENT; // e_ident occupies bytes [0,16); fields below start at 16.
    let e_machine = rd_u16(image, 18, "e_machine")?;
    if e_machine != EM_X86_64 {
        return Err(LoaderError::BadMachine(e_machine));
    }
    let e_phoff = rd_u64(image, 32, "e_phoff")? as usize;
    let e_phentsize = rd_u16(image, 54, "e_phentsize")? as usize;
    let e_phnum = rd_u16(image, 56, "e_phnum")? as usize;
    if e_phentsize < PHDR_SIZE {
        return Err(LoaderError::Truncated("e_phentsize"));
    }

    let mut phdrs = Vec::with_capacity(e_phnum);
    for i in 0..e_phnum {
        let base = e_phoff + i * e_phentsize;
        phdrs.push(Phdr {
            p_type: rd_u32(image, base, "p_type")?,
            p_offset: rd_u64(image, base + 8, "p_offset")?,
            p_paddr: rd_u64(image, base + 24, "p_paddr")?,
            p_filesz: rd_u64(image, base + 32, "p_filesz")?,
            p_memsz: rd_u64(image, base + 40, "p_memsz")?,
        });
    }
    Ok(phdrs)
}

/// Find the TABOS 64-bit entry from a `PT_NOTE` segment, if present.
fn find_tb_entry(image: &[u8], phdrs: &[Phdr]) -> Result<Option<u64>, LoaderError> {
    for ph in phdrs.iter().filter(|p| p.p_type == PT_NOTE) {
        let start = ph.p_offset as usize;
        let end = start
            .checked_add(ph.p_filesz as usize)
            .ok_or(LoaderError::Truncated("PT_NOTE"))?;
        let seg = image.get(start..end).ok_or(LoaderError::Truncated("PT_NOTE"))?;

        let mut off = 0usize;
        while off + 12 <= seg.len() {
            let namesz = u32::from_le_bytes([seg[off], seg[off + 1], seg[off + 2], seg[off + 3]])
                as usize;
            let descsz = u32::from_le_bytes([
                seg[off + 4],
                seg[off + 5],
                seg[off + 6],
                seg[off + 7],
            ]) as usize;
            let ntype = u32::from_le_bytes([
                seg[off + 8],
                seg[off + 9],
                seg[off + 10],
                seg[off + 11],
            ]);

            let name_off = off + 12;
            let desc_off = name_off + align4(namesz);
            let next = desc_off + align4(descsz);
            if next > seg.len() || next <= off {
                break; // malformed / final padding
            }

            let name = &seg[name_off..name_off + namesz];
            let name_trimmed = name.strip_suffix(b"\0").unwrap_or(name);
            if ntype == tb_boot::TB_NOTE_TYPE_ENTRY64
                && name_trimmed == tb_boot::TB_NOTE_NAME.as_bytes()
                && descsz >= 8
            {
                let d = &seg[desc_off..desc_off + 8];
                let entry = u64::from_le_bytes([
                    d[0], d[1], d[2], d[3], d[4], d[5], d[6], d[7],
                ]);
                return Ok(Some(entry));
            }
            off = next;
        }
    }
    Ok(None)
}

/// Parse, copy every `PT_LOAD` to its `p_paddr` in guest RAM, and resolve the
/// 64-bit entry (TABOS note preferred, `e_entry` fallback).
pub fn load_kernel(image: &[u8], mem: &GuestMemoryMmap) -> Result<LoadedKernel, LoaderError> {
    let phdrs = parse_phdrs(image)?;
    let e_entry = rd_u64(image, 24, "e_entry")?;

    let mut loaded_any = false;
    let mut image_end = 0u64;

    for (index, ph) in phdrs.iter().enumerate() {
        if ph.p_type != PT_LOAD || ph.p_memsz == 0 {
            continue;
        }
        if ph.p_filesz > ph.p_memsz {
            return Err(LoaderError::BadSegmentSize { index });
        }

        // Copy the file-backed bytes.
        let foff = ph.p_offset as usize;
        let fsz = ph.p_filesz as usize;
        let src = image
            .get(foff..foff + fsz)
            .ok_or(LoaderError::SegmentOutOfFile { index })?;
        mem.write_slice(src, GuestAddress(ph.p_paddr))
            .map_err(|e| LoaderError::GuestWrite {
                paddr: ph.p_paddr,
                detail: e.to_string(),
            })?;

        // Zero the .bss tail (p_memsz - p_filesz). Guest RAM is already zeroed,
        // but we do it explicitly so loading into reused memory is correct.
        let bss = (ph.p_memsz - ph.p_filesz) as usize;
        if bss > 0 {
            let zeros = vec![0u8; bss];
            let dst = ph.p_paddr + ph.p_filesz;
            mem.write_slice(&zeros, GuestAddress(dst))
                .map_err(|e| LoaderError::GuestWrite {
                    paddr: dst,
                    detail: e.to_string(),
                })?;
        }

        loaded_any = true;
        image_end = image_end.max(ph.p_paddr + ph.p_memsz);
    }

    if !loaded_any {
        return Err(LoaderError::NoLoadSegments);
    }

    let (entry, entry_from_note) = match find_tb_entry(image, &phdrs)? {
        Some(e) => (e, true),
        None => (e_entry, false),
    };

    Ok(LoadedKernel {
        entry,
        entry_from_note,
        image_end,
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use vm_memory::{Bytes, GuestAddress, GuestMemoryMmap};

    fn w16(b: &mut [u8], off: usize, v: u16) {
        b[off..off + 2].copy_from_slice(&v.to_le_bytes());
    }
    fn w32(b: &mut [u8], off: usize, v: u32) {
        b[off..off + 4].copy_from_slice(&v.to_le_bytes());
    }
    fn w64(b: &mut [u8], off: usize, v: u64) {
        b[off..off + 8].copy_from_slice(&v.to_le_bytes());
    }

    /// Build a minimal ET_EXEC ELF64 with one PT_LOAD (payload \"ABCD\" at
    /// paddr 0x100000, +4 bytes bss) and, optionally, a PT_NOTE TABOS entry.
    fn build_elf(note_entry: Option<u64>, e_entry: u64) -> Vec<u8> {
        let mut buf = vec![0u8; 0x400];
        buf[0..4].copy_from_slice(b"\x7fELF");
        buf[4] = ELFCLASS64;
        buf[5] = ELFDATA2LSB;
        buf[6] = 1; // EV_CURRENT
        w16(&mut buf, 16, 2); // e_type = ET_EXEC
        w16(&mut buf, 18, EM_X86_64);
        w32(&mut buf, 20, 1); // e_version
        w64(&mut buf, 24, e_entry); // e_entry
        w64(&mut buf, 32, EHDR_SIZE as u64); // e_phoff
        w16(&mut buf, 52, EHDR_SIZE as u16); // e_ehsize
        w16(&mut buf, 54, PHDR_SIZE as u16); // e_phentsize
        let phnum = if note_entry.is_some() { 2u16 } else { 1 };
        w16(&mut buf, 56, phnum); // e_phnum

        // PT_LOAD
        let ph0 = EHDR_SIZE;
        w32(&mut buf, ph0, PT_LOAD);
        w32(&mut buf, ph0 + 4, 5); // R E
        w64(&mut buf, ph0 + 8, 0x200); // p_offset
        w64(&mut buf, ph0 + 16, 0x100000); // p_vaddr
        w64(&mut buf, ph0 + 24, 0x100000); // p_paddr
        w64(&mut buf, ph0 + 32, 4); // p_filesz
        w64(&mut buf, ph0 + 40, 8); // p_memsz (4 bss)
        w64(&mut buf, ph0 + 48, 0x1000); // p_align
        buf[0x200..0x204].copy_from_slice(b"ABCD");

        if let Some(entry) = note_entry {
            let ph1 = EHDR_SIZE + PHDR_SIZE;
            let note_off = 0x300usize;
            let mut note = Vec::new();
            note.extend_from_slice(&6u32.to_le_bytes()); // namesz \"TABOS\0\"
            note.extend_from_slice(&8u32.to_le_bytes()); // descsz
            note.extend_from_slice(&tb_boot::TB_NOTE_TYPE_ENTRY64.to_le_bytes());
            note.extend_from_slice(b"TABOS\0"); // 6 bytes
            note.extend_from_slice(&[0u8, 0u8]); // pad name 6 -> 8
            note.extend_from_slice(&entry.to_le_bytes()); // 8-byte desc
            let nlen = note.len();
            buf[note_off..note_off + nlen].copy_from_slice(&note);
            w32(&mut buf, ph1, PT_NOTE);
            w32(&mut buf, ph1 + 4, 4); // R
            w64(&mut buf, ph1 + 8, note_off as u64); // p_offset
            w64(&mut buf, ph1 + 32, nlen as u64); // p_filesz
            w64(&mut buf, ph1 + 40, nlen as u64); // p_memsz
            w64(&mut buf, ph1 + 48, 4); // p_align
        }
        buf
    }

    fn mem() -> GuestMemoryMmap {
        GuestMemoryMmap::from_ranges(&[(GuestAddress(0), 0x200000)]).unwrap()
    }

    #[test]
    fn loads_segment_and_prefers_note_entry() {
        let elf = build_elf(Some(0x0012_3456), 0x0010_0000);
        let gm = mem();
        let loaded = load_kernel(&elf, &gm).unwrap();

        assert!(loaded.entry_from_note);
        assert_eq!(loaded.entry, 0x0012_3456);
        assert_eq!(loaded.image_end, 0x0010_0000 + 8);

        let mut got = [0u8; 4];
        gm.read_slice(&mut got, GuestAddress(0x0010_0000)).unwrap();
        assert_eq!(&got, b"ABCD");
        // bss tail is zeroed
        let mut bss = [0xffu8; 4];
        gm.read_slice(&mut bss, GuestAddress(0x0010_0004)).unwrap();
        assert_eq!(bss, [0, 0, 0, 0]);
    }

    #[test]
    fn falls_back_to_e_entry_without_note() {
        let elf = build_elf(None, 0x0010_0000);
        let gm = mem();
        let loaded = load_kernel(&elf, &gm).unwrap();
        assert!(!loaded.entry_from_note);
        assert_eq!(loaded.entry, 0x0010_0000);
    }

    #[test]
    fn rejects_bad_magic() {
        let mut elf = build_elf(None, 0x100000);
        elf[1] = b'X';
        assert_eq!(load_kernel(&elf, &mem()).unwrap_err(), LoaderError::BadMagic);
    }

    #[test]
    fn rejects_non_x86_64() {
        let mut elf = build_elf(None, 0x100000);
        w16(&mut elf, 18, 0xB7); // aarch64
        assert_eq!(
            load_kernel(&elf, &mem()).unwrap_err(),
            LoaderError::BadMachine(0xB7)
        );
    }

    #[test]
    fn rejects_segment_past_eof() {
        let mut elf = build_elf(None, 0x100000);
        // Make PT_LOAD p_filesz huge so it runs past the file.
        w64(&mut elf, EHDR_SIZE + 32, 0x10_0000);
        w64(&mut elf, EHDR_SIZE + 40, 0x10_0000);
        assert_eq!(
            load_kernel(&elf, &mem()).unwrap_err(),
            LoaderError::SegmentOutOfFile { index: 0 }
        );
    }
}

//! Device-bus abstraction: a PIO/MMIO address-range registry that dispatches
//! guest I/O to registered devices. Deliberately transport-agnostic so a virtio
//! MMIO transport can be added later as just another [`BusDevice`].
//!
//! Modelled on the rust-vmm / Firecracker `Bus` pattern (a sorted map from base
//! address to device, dispatched by the largest base <= addr).

use std::collections::BTreeMap;
use std::fmt;
use std::sync::{Arc, Mutex};

/// A device that occupies a contiguous address range on a bus. Offsets passed
/// to [`BusDevice::read`]/[`BusDevice::write`] are relative to the device base.
///
/// `Send` so devices can later be shared with an I/O thread (e.g. a serial
/// input pump); the current single-threaded run loop never contends the mutex.
pub trait BusDevice: Send {
    /// Handle a guest read at `offset` within this device, filling `data`.
    fn read(&mut self, offset: u64, data: &mut [u8]);
    /// Handle a guest write of `data` at `offset` within this device.
    fn write(&mut self, offset: u64, data: &[u8]);
}

/// Shared, lockable device handle stored on a bus.
pub type SharedDevice = Arc<Mutex<dyn BusDevice>>;

/// Error registering a device on a bus.
#[derive(Debug, PartialEq, Eq)]
pub enum BusError {
    /// A zero-length range was requested.
    ZeroLength,
    /// The requested range overlaps an already-registered device.
    Overlap {
        /// Requested base.
        base: u64,
        /// Requested length.
        len: u64,
    },
}

impl fmt::Display for BusError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            BusError::ZeroLength => write!(f, "device range has zero length"),
            BusError::Overlap { base, len } => {
                write!(f, "device range [{base:#x}, {:#x}) overlaps an existing device", base + len)
            }
        }
    }
}

impl std::error::Error for BusError {}

struct Entry {
    len: u64,
    device: SharedDevice,
}

/// An I/O bus: a sorted registry of devices keyed by base address.
#[derive(Default)]
pub struct Bus {
    entries: BTreeMap<u64, Entry>,
}

impl Bus {
    /// A new, empty bus.
    pub fn new() -> Self {
        Bus {
            entries: BTreeMap::new(),
        }
    }

    /// Register `device` covering `[base, base + len)`. Errors on overlap.
    pub fn register(&mut self, base: u64, len: u64, device: SharedDevice) -> Result<(), BusError> {
        if len == 0 {
            return Err(BusError::ZeroLength);
        }
        let end = base.saturating_add(len);
        // Overlap check against the neighbour at-or-before and the one after.
        if let Some((&pbase, pentry)) = self.entries.range(..=base).next_back() {
            if pbase + pentry.len > base {
                return Err(BusError::Overlap { base, len });
            }
        }
        if let Some((&nbase, _)) = self.entries.range(base..).next() {
            if nbase < end {
                return Err(BusError::Overlap { base, len });
            }
        }
        self.entries.insert(base, Entry { len, device });
        Ok(())
    }

    /// Find the device whose range contains `addr`, returning its base.
    fn lookup(&self, addr: u64) -> Option<(u64, &SharedDevice)> {
        let (&base, entry) = self.entries.range(..=addr).next_back()?;
        if addr < base + entry.len {
            Some((base, &entry.device))
        } else {
            None
        }
    }

    /// Dispatch a guest read at absolute `addr`. Unclaimed reads return all-ones
    /// (open-bus), matching real hardware and never stalling the guest.
    pub fn read(&self, addr: u64, data: &mut [u8]) {
        match self.lookup(addr) {
            Some((base, device)) => device
                .lock()
                .expect("device mutex poisoned")
                .read(addr - base, data),
            None => data.fill(0xff),
        }
    }

    /// Dispatch a guest write at absolute `addr`. Unclaimed writes are dropped.
    pub fn write(&self, addr: u64, data: &[u8]) {
        if let Some((base, device)) = self.lookup(addr) {
            device
                .lock()
                .expect("device mutex poisoned")
                .write(addr - base, data);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[derive(Default)]
    struct Probe {
        last_write: Option<(u64, Vec<u8>)>,
        read_fill: u8,
    }
    impl BusDevice for Probe {
        fn read(&mut self, offset: u64, data: &mut [u8]) {
            data.fill(self.read_fill);
            // encode the offset in the first byte so tests can check dispatch
            if let Some(b) = data.first_mut() {
                *b = offset as u8;
            }
        }
        fn write(&mut self, offset: u64, data: &[u8]) {
            self.last_write = Some((offset, data.to_vec()));
        }
    }

    fn probe() -> Arc<Mutex<Probe>> {
        Arc::new(Mutex::new(Probe::default()))
    }

    #[test]
    fn dispatch_translates_offset() {
        let mut bus = Bus::new();
        let p = probe();
        bus.register(0x3f8, 8, p.clone()).unwrap();

        bus.write(0x3fd, &[0xAB]);
        let got = p.lock().unwrap().last_write.clone().unwrap();
        assert_eq!(got.0, 5); // 0x3fd - 0x3f8
        assert_eq!(got.1, vec![0xAB]);

        let mut data = [0u8; 1];
        bus.read(0x3fa, &mut data);
        assert_eq!(data[0], 2); // offset 2 echoed back
    }

    #[test]
    fn unclaimed_read_is_open_bus() {
        let bus = Bus::new();
        let mut data = [0u8; 2];
        bus.read(0x1234, &mut data);
        assert_eq!(data, [0xff, 0xff]);
    }

    #[test]
    fn overlap_is_rejected() {
        let mut bus = Bus::new();
        bus.register(0x100, 0x10, probe()).unwrap();
        assert_eq!(
            bus.register(0x108, 0x10, probe()).unwrap_err(),
            BusError::Overlap { base: 0x108, len: 0x10 }
        );
        // Adjacent, non-overlapping is fine.
        bus.register(0x110, 0x10, probe()).unwrap();
    }

    #[test]
    fn zero_length_is_rejected() {
        let mut bus = Bus::new();
        assert_eq!(bus.register(0x100, 0, probe()).unwrap_err(), BusError::ZeroLength);
    }
}

//! A minimal 16550A UART (COM1-class) device.
//!
//! It carries guest serial output to a host writer (stdout in production) so CI
//! can grep the milestone markers, and supports input via an injectable queue.
//! It is matched exactly to the kernel's polled TX driver
//! (crates/tb-hal/src/arch/x86_64/serial.rs): the guest writes one byte at a
//! time after spinning on LSR bit 5 (THRE), so we must always report THRE set,
//! and we must honour DLAB so the init-time divisor write to THR is NOT printed.
//!
//! Register map (offsets from base, National 16550 / OSDev \"Serial Ports\"):
//!   0  THR/RBR  (DLAB=0) | DLL  (DLAB=1)
//!   1  IER      (DLAB=0) | DLM  (DLAB=1)
//!   2  IIR (r) / FCR (w)
//!   3  LCR  (bit 7 = DLAB)
//!   4  MCR
//!   5  LSR  (bit 5 = THRE, bit 6 = TEMT, bit 0 = DR)
//!   6  MSR
//!   7  SCR  (scratch)

use std::collections::VecDeque;
use std::io::Write;

use crate::device::BusDevice;

const REG_DATA: u64 = 0; // THR (w) / RBR (r) / DLL (DLAB)
const REG_IER: u64 = 1; // IER / DLM (DLAB)
const REG_IIR_FCR: u64 = 2;
const REG_LCR: u64 = 3;
const REG_MCR: u64 = 4;
const REG_LSR: u64 = 5;
const REG_MSR: u64 = 6;
const REG_SCR: u64 = 7;

const LCR_DLAB: u8 = 0x80;
const LSR_DR: u8 = 0x01; // data ready (input available)
const LSR_THRE: u8 = 0x20; // transmit holding register empty
const LSR_TEMT: u8 = 0x40; // transmitter empty
const MSR_DEFAULT: u8 = 0xB0; // DCD | DSR | CTS asserted (typical idle modem state)
const IIR_NO_INT: u8 = 0x01; // no interrupt pending

/// A 16550A UART writing transmitted bytes to `out`.
pub struct Serial {
    ier: u8,
    lcr: u8,
    mcr: u8,
    scr: u8,
    fcr: u8,
    dll: u8,
    dlm: u8,
    input: VecDeque<u8>,
    out: Box<dyn Write + Send>,
}

impl Serial {
    /// A new UART transmitting to `out`.
    pub fn new(out: Box<dyn Write + Send>) -> Self {
        Serial {
            ier: 0,
            lcr: 0,
            mcr: 0,
            scr: 0,
            fcr: 0,
            dll: 0,
            dlm: 0,
            input: VecDeque::new(),
            out,
        }
    }

    /// Queue bytes as guest input (drained by guest reads of RBR). Unused by the
    /// M0-M4 boot, which is output-only, but keeps the device complete.
    #[allow(dead_code)]
    pub fn enqueue_input(&mut self, bytes: &[u8]) {
        self.input.extend(bytes.iter().copied());
    }

    fn dlab(&self) -> bool {
        self.lcr & LCR_DLAB != 0
    }

    fn line_status(&self) -> u8 {
        let mut lsr = LSR_THRE | LSR_TEMT; // always ready to transmit
        if !self.input.is_empty() {
            lsr |= LSR_DR;
        }
        lsr
    }

    fn transmit(&mut self, byte: u8) {
        // Best-effort: a closed stdout must not crash the VMM. Flush each byte
        // so piped CI output (block-buffered) shows markers promptly.
        let _ = self.out.write_all(&[byte]);
        let _ = self.out.flush();
    }
}

impl BusDevice for Serial {
    fn read(&mut self, offset: u64, data: &mut [u8]) {
        let value = match offset {
            REG_DATA => {
                if self.dlab() {
                    self.dll
                } else {
                    self.input.pop_front().unwrap_or(0)
                }
            }
            REG_IER => {
                if self.dlab() {
                    self.dlm
                } else {
                    self.ier
                }
            }
            REG_IIR_FCR => IIR_NO_INT,
            REG_LCR => self.lcr,
            REG_MCR => self.mcr,
            REG_LSR => self.line_status(),
            REG_MSR => MSR_DEFAULT,
            REG_SCR => self.scr,
            _ => 0,
        };
        if let Some(b) = data.first_mut() {
            *b = value;
        }
        for b in data.iter_mut().skip(1) {
            *b = 0;
        }
    }

    fn write(&mut self, offset: u64, data: &[u8]) {
        let Some(&value) = data.first() else {
            return;
        };
        match offset {
            REG_DATA => {
                if self.dlab() {
                    self.dll = value; // divisor latch low — NOT transmitted
                } else {
                    self.transmit(value);
                }
            }
            REG_IER => {
                if self.dlab() {
                    self.dlm = value; // divisor latch high
                } else {
                    self.ier = value;
                }
            }
            REG_IIR_FCR => self.fcr = value, // FIFO control
            REG_LCR => self.lcr = value,     // updates DLAB
            REG_MCR => self.mcr = value,
            REG_SCR => self.scr = value,
            // LSR (5) and MSR (6) are read-only; ignore writes.
            _ => {}
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::{Arc, Mutex};

    /// A `Write` that appends into a shared buffer the test can inspect.
    #[derive(Clone)]
    struct SharedBuf(Arc<Mutex<Vec<u8>>>);
    impl Write for SharedBuf {
        fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
            self.0.lock().unwrap().extend_from_slice(buf);
            Ok(buf.len())
        }
        fn flush(&mut self) -> std::io::Result<()> {
            Ok(())
        }
    }

    fn serial_with_buf() -> (Serial, Arc<Mutex<Vec<u8>>>) {
        let buf = Arc::new(Mutex::new(Vec::new()));
        (Serial::new(Box::new(SharedBuf(buf.clone()))), buf)
    }

    #[test]
    fn lsr_always_reports_thre() {
        let (mut s, _) = serial_with_buf();
        let mut d = [0u8; 1];
        s.read(REG_LSR, &mut d);
        assert_ne!(d[0] & LSR_THRE, 0, "guest TX loop spins forever without THRE");
    }

    #[test]
    fn init_divisor_write_is_not_printed_then_char_is() {
        // Mirror the kernel's serial_init() ordering for the DLAB-sensitive part.
        let (mut s, buf) = serial_with_buf();
        s.write(REG_LCR, &[0x80]); // DLAB = 1
        s.write(REG_DATA, &[0x01]); // DLL divisor — must NOT be emitted
        s.write(REG_IER, &[0x00]); // DLM divisor
        s.write(REG_LCR, &[0x03]); // DLAB = 0, 8N1
        assert!(buf.lock().unwrap().is_empty(), "divisor latch byte leaked to output");

        s.write(REG_DATA, &[b'H']); // now a real character
        s.write(REG_DATA, &[b'i']);
        assert_eq!(&*buf.lock().unwrap(), b"Hi");
    }

    #[test]
    fn input_queue_sets_dr_and_drains() {
        let (mut s, _) = serial_with_buf();
        s.enqueue_input(b"AB");
        let mut lsr = [0u8; 1];
        s.read(REG_LSR, &mut lsr);
        assert_ne!(lsr[0] & LSR_DR, 0);

        let mut d = [0u8; 1];
        s.read(REG_DATA, &mut d);
        assert_eq!(d[0], b'A');
        s.read(REG_DATA, &mut d);
        assert_eq!(d[0], b'B');
        s.read(REG_LSR, &mut lsr);
        assert_eq!(lsr[0] & LSR_DR, 0, "DR clears when the input queue empties");
    }
}

//! Architecture seam.
//!
//! tb-vmm targets **x86_64** today with a clean arch boundary so **aarch64 is a
//! documented follow-up** (it would add `arch/aarch64/boot.rs` implementing the
//! `KVM_ARM_VCPU_INIT` + `KVM_SET_ONE_REG` path described in
//! docs/SOVEREIGNTY-ROADMAP.md §7, and register itself in [`setup`]).
//!
//! Everything arch-specific about turning a loaded kernel into a runnable vCPU
//! (page tables, GDT, the boot-info block, and the long-mode `KVM_SET_SREGS`/
//! `KVM_SET_REGS`) lives behind the single [`setup`] entry point.

use kvm_ioctls::{Kvm, VcpuFd, VmFd};
use vm_memory::GuestMemoryMmap;

use crate::error::VmmError;
use crate::memory::MemRegion;

#[cfg(target_arch = "x86_64")]
pub mod x86_64;

/// Arch-neutral inputs the boot configurator needs.
pub struct BootParams<'a> {
    /// Guest physical address to begin executing at (the kernel's tb-boot entry).
    pub entry_point: u64,
    /// The guest's logical memory map, reported to the kernel via tb-boot.
    pub mem_regions: &'a [MemRegion],
    /// The kernel command line.
    pub cmdline: &'a str,
}

/// Configure the VM + vCPU for a direct boot of `params.entry_point`.
///
/// Writes the arch boot structures into guest RAM and programs the vCPU's
/// special + general registers. After this returns the vCPU is ready for its
/// first `KVM_RUN`.
pub fn setup(
    kvm: &Kvm,
    vm: &VmFd,
    vcpu: &VcpuFd,
    mem: &GuestMemoryMmap,
    params: &BootParams,
) -> Result<(), VmmError> {
    #[cfg(target_arch = "x86_64")]
    {
        x86_64::boot::setup(kvm, vm, vcpu, mem, params)
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        let _ = (kvm, vm, vcpu, mem, params);
        Err(VmmError::Unsupported(
            "tb-vmm host arch: only x86_64 is implemented (aarch64 is a documented follow-up)",
        ))
    }
}

//! x86_64 `tb-boot v0` guest setup — **enter the guest directly in 64-bit long
//! mode**, deleting the PVH note + the A0 32->64 trampoline from the boot path.
//!
//! Every constant here is taken VERBATIM from Firecracker's verified sources and
//! cited inline; do not invent KVM struct fields or descriptor bits.
//!  * GDT encoding (`gdt_entry`, `kvm_segment_from_gdt`):
//!    Firecracker `src/vmm/src/arch/x86_64/gdt.rs`.
//!  * Long-mode GDT table, `KVM_SET_SREGS` cr0/cr3/cr4/efer, identity page
//!    tables, and `KVM_SET_REGS` rflags/rip: Firecracker
//!    `src/vmm/src/arch/x86_64/regs.rs` (the `BootProtocol::LinuxBoot` arm).
//!  * `kvm_sregs`/`kvm_regs`/`kvm_segment` layout, `KVM_SET_USER_MEMORY_REGION`:
//!    <https://docs.kernel.org/virt/kvm/api.html>.
//!
//! Low-memory map (all below 1 MiB; identity-mapped by the page tables below):
//! ```text
//!   0x0500  boot GDT (4 x u64)             [Firecracker BOOT_GDT_OFFSET]
//!   0x0520  boot IDT (zeroed)             [Firecracker BOOT_IDT_OFFSET]
//!   0x6000  TbBootInfo (56 bytes)          [tb-boot v0]
//!   0x6040  TbMemRegion array             [tb-boot v0]
//!   0x6800  cmdline (NUL-terminated)       [tb-boot v0]
//!   0x9000  PML4                          [Firecracker PML4_START]
//!   0xa000  PDPTE                         [Firecracker PDPTE_START]
//!   0xb000  PDE (512 x 2 MiB, [0,1 GiB))   [Firecracker PDE_START]
//! ```

use kvm_bindings::{kvm_regs, kvm_segment, kvm_sregs, KVM_MAX_CPUID_ENTRIES};
use kvm_ioctls::{Kvm, VcpuFd, VmFd};
use vm_memory::{Address, Bytes, GuestAddress, GuestMemory, GuestMemoryMmap};

use crate::arch::BootParams;
use crate::error::VmmError;
use crate::memory::MemRegion;

// --- Firecracker low-memory offsets (regs.rs) ------------------------------
const BOOT_GDT_OFFSET: u64 = 0x500;
const BOOT_IDT_OFFSET: u64 = 0x520;
const PML4_START: u64 = 0x9000;
const PDPTE_START: u64 = 0xa000;
const PDE_START: u64 = 0xb000;
const BOOT_GDT_MAX: usize = 4;

// --- tb-boot v0 structure placement ---------------------------------------
const TB_BOOT_INFO_ADDR: u64 = 0x6000;
const TB_MEM_REGIONS_ADDR: u64 = 0x6040;
const TB_CMDLINE_ADDR: u64 = 0x6800;
/// Boot structures must stay below the page tables.
const TB_LOWMEM_LIMIT: u64 = PML4_START;

/// Serialized size of [`tb_boot::TbBootInfo`] (repr(C)).
const TB_BOOT_INFO_SIZE: usize = 56;
/// Serialized size of [`tb_boot::TbMemRegion`] (repr(C)).
const TB_MEM_REGION_SIZE: usize = 24;

// Compile-time ABI guards: if tb-boot ever changes its struct layout, this
// breaks the build instead of silently writing a mismatched boot block.
const _: () = assert!(std::mem::size_of::<tb_boot::TbBootInfo>() == TB_BOOT_INFO_SIZE);
const _: () = assert!(std::mem::size_of::<tb_boot::TbMemRegion>() == TB_MEM_REGION_SIZE);

// --- Control-register bits (regs.rs) ---------------------------------------
const X86_CR0_PE: u64 = 0x1;
const X86_CR0_PG: u64 = 0x8000_0000;
const X86_CR4_PAE: u64 = 0x20;
const EFER_LME: u64 = 0x100;
const EFER_LMA: u64 = 0x400;

/// KVM's internal real-mode TSS region (Firecracker arch/x86_64/mod.rs).
const KVM_TSS_ADDRESS: usize = 0xfffb_d000;

// ===========================================================================
// GDT encoding — verbatim from Firecracker gdt.rs (cited).
// ===========================================================================

/// Constructor for a conventional segment GDT entry (Linux `segment.h`).
/// Verbatim from Firecracker `gdt.rs::gdt_entry`.
pub(crate) fn gdt_entry(flags: u16, base: u32, limit: u32) -> u64 {
    ((u64::from(base) & 0xff00_0000u64) << (56 - 24))
        | ((u64::from(flags) & 0x0000_f0ffu64) << 40)
        | ((u64::from(limit) & 0x000f_0000u64) << (48 - 16))
        | ((u64::from(base) & 0x00ff_ffffu64) << 16)
        | (u64::from(limit) & 0x0000_ffffu64)
}

fn get_base(entry: u64) -> u64 {
    (((entry) & 0xFF00_0000_0000_0000) >> 32)
        | (((entry) & 0x0000_00FF_0000_0000) >> 16)
        | (((entry) & 0x0000_0000_FFFF_0000) >> 16)
}

fn get_limit(entry: u64) -> u32 {
    let limit: u32 =
        ((((entry) & 0x000F_0000_0000_0000) >> 32) | ((entry) & 0x0000_0000_0000_FFFF)) as u32;
    match get_g(entry) {
        0 => limit,
        _ => (limit << 12) | 0xFFF,
    }
}

fn get_g(entry: u64) -> u8 {
    ((entry & 0x0080_0000_0000_0000) >> 55) as u8
}
fn get_db(entry: u64) -> u8 {
    ((entry & 0x0040_0000_0000_0000) >> 54) as u8
}
fn get_l(entry: u64) -> u8 {
    ((entry & 0x0020_0000_0000_0000) >> 53) as u8
}
fn get_avl(entry: u64) -> u8 {
    ((entry & 0x0010_0000_0000_0000) >> 52) as u8
}
fn get_p(entry: u64) -> u8 {
    ((entry & 0x0000_8000_0000_0000) >> 47) as u8
}
fn get_dpl(entry: u64) -> u8 {
    ((entry & 0x0000_6000_0000_0000) >> 45) as u8
}
fn get_s(entry: u64) -> u8 {
    ((entry & 0x0000_1000_0000_0000) >> 44) as u8
}
fn get_type(entry: u64) -> u8 {
    ((entry & 0x0000_0F00_0000_0000) >> 40) as u8
}

/// Build a `kvm_segment` from a GDT entry + its table index.
/// Verbatim from Firecracker `gdt.rs::kvm_segment_from_gdt`.
pub(crate) fn kvm_segment_from_gdt(entry: u64, table_index: u8) -> kvm_segment {
    kvm_segment {
        base: get_base(entry),
        limit: get_limit(entry),
        selector: u16::from(table_index * 8),
        type_: get_type(entry),
        present: get_p(entry),
        dpl: get_dpl(entry),
        db: get_db(entry),
        s: get_s(entry),
        l: get_l(entry),
        g: get_g(entry),
        avl: get_avl(entry),
        padding: 0,
        unusable: match get_p(entry) {
            0 => 1,
            _ => 0,
        },
    }
}

/// The flat 64-bit boot GDT (Firecracker `BootProtocol::LinuxBoot`): NULL, a
/// 64-bit code segment (L=1), a flat data segment, and a TSS descriptor.
fn gdt_table() -> [u64; BOOT_GDT_MAX] {
    [
        gdt_entry(0, 0, 0),            // NULL
        gdt_entry(0xa09b, 0, 0xfffff), // CODE: present, ring0, exec/read, L=1, G=1
        gdt_entry(0xc093, 0, 0xfffff), // DATA: present, ring0, read/write, DB=1, G=1
        gdt_entry(0x808b, 0, 0xfffff), // TSS
    ]
}

// ===========================================================================
// Guest-RAM boot structures.
// ===========================================================================

fn write_gdt(mem: &GuestMemoryMmap) -> Result<(), VmmError> {
    for (i, entry) in gdt_table().iter().enumerate() {
        mem.write_obj(*entry, GuestAddress(BOOT_GDT_OFFSET + (i as u64) * 8))?;
    }
    Ok(())
}

fn write_idt(mem: &GuestMemoryMmap) -> Result<(), VmmError> {
    mem.write_obj(0u64, GuestAddress(BOOT_IDT_OFFSET))?;
    Ok(())
}

/// Identity page tables covering VA [0, 1 GiB) with 2 MiB pages.
/// Verbatim structure from Firecracker `regs.rs::setup_page_tables`.
fn setup_page_tables(mem: &GuestMemoryMmap) -> Result<(), VmmError> {
    mem.write_obj(PDPTE_START | 0x03u64, GuestAddress(PML4_START))?; // PML4[0] -> PDPTE
    mem.write_obj(PDE_START | 0x03u64, GuestAddress(PDPTE_START))?; // PDPTE[0] -> PDE
    for i in 0..512u64 {
        // PDE[i] = (i*2MiB) | PRESENT|WRITE|PS
        mem.write_obj((i << 21) | 0x83u64, GuestAddress(PDE_START + i * 8))?;
    }
    Ok(())
}

/// Serialize a [`tb_boot::TbMemRegion`] (repr(C): base,len,kind,_pad).
pub(crate) fn serialize_mem_region(base: u64, len: u64, kind: u32) -> [u8; TB_MEM_REGION_SIZE] {
    let mut b = [0u8; TB_MEM_REGION_SIZE];
    b[0..8].copy_from_slice(&base.to_le_bytes());
    b[8..16].copy_from_slice(&len.to_le_bytes());
    b[16..20].copy_from_slice(&kind.to_le_bytes());
    // b[20..24] = _pad (0)
    b
}

/// Serialize a [`tb_boot::TbBootInfo`] (repr(C)).
#[allow(clippy::too_many_arguments)]
pub(crate) fn serialize_boot_info(
    magic: u64,
    version: u32,
    flags: u32,
    mem_regions_ptr: u64,
    mem_regions_len: u64,
    cmdline_ptr: u64,
    cmdline_len: u64,
    kernel_entry: u64,
) -> [u8; TB_BOOT_INFO_SIZE] {
    let mut b = [0u8; TB_BOOT_INFO_SIZE];
    b[0..8].copy_from_slice(&magic.to_le_bytes());
    b[8..12].copy_from_slice(&version.to_le_bytes());
    b[12..16].copy_from_slice(&flags.to_le_bytes());
    b[16..24].copy_from_slice(&mem_regions_ptr.to_le_bytes());
    b[24..32].copy_from_slice(&mem_regions_len.to_le_bytes());
    b[32..40].copy_from_slice(&cmdline_ptr.to_le_bytes());
    b[40..48].copy_from_slice(&cmdline_len.to_le_bytes());
    b[48..56].copy_from_slice(&kernel_entry.to_le_bytes());
    b
}

/// Write GDT, IDT, page tables, the TbMemRegion array, the cmdline, and the
/// TbBootInfo block into guest RAM. Returns the guest-physical TbBootInfo addr.
fn write_system_memory(mem: &GuestMemoryMmap, params: &BootParams) -> Result<u64, VmmError> {
    let n = params.mem_regions.len();
    let regions_end = TB_MEM_REGIONS_ADDR + (n as u64) * (TB_MEM_REGION_SIZE as u64);
    if regions_end > TB_CMDLINE_ADDR {
        return Err(VmmError::Config(
            "too many memory regions for the tb-boot low-memory window".into(),
        ));
    }
    let cmd = params.cmdline.as_bytes();
    if TB_CMDLINE_ADDR + cmd.len() as u64 + 1 > TB_LOWMEM_LIMIT {
        return Err(VmmError::Config("kernel cmdline too long for the boot window".into()));
    }

    write_gdt(mem)?;
    write_idt(mem)?;
    setup_page_tables(mem)?;

    for (i, r) in params.mem_regions.iter().enumerate() {
        let bytes = serialize_mem_region(r.base, r.len, r.kind as u32);
        mem.write_slice(
            &bytes,
            GuestAddress(TB_MEM_REGIONS_ADDR + (i as u64) * (TB_MEM_REGION_SIZE as u64)),
        )?;
    }

    mem.write_slice(cmd, GuestAddress(TB_CMDLINE_ADDR))?;
    mem.write_obj(0u8, GuestAddress(TB_CMDLINE_ADDR + cmd.len() as u64))?; // NUL

    let info = serialize_boot_info(
        tb_boot::TB_BOOT_MAGIC,
        tb_boot::TB_BOOT_VERSION,
        0, // flags
        TB_MEM_REGIONS_ADDR,
        n as u64,
        TB_CMDLINE_ADDR,
        cmd.len() as u64,
        params.entry_point,
    );
    mem.write_slice(&info, GuestAddress(TB_BOOT_INFO_ADDR))?;

    Ok(TB_BOOT_INFO_ADDR)
}

// ===========================================================================
// vCPU programming.
// ===========================================================================

/// `KVM_SET_SREGS`: long-mode segments + control registers.
/// Mirrors Firecracker `regs.rs` `configure_segments_and_sregs` +
/// `setup_page_tables` for `BootProtocol::LinuxBoot`.
fn setup_sregs(vcpu: &VcpuFd) -> Result<(), VmmError> {
    let mut sregs: kvm_sregs = vcpu.get_sregs()?;
    let gdt = gdt_table();

    let code_seg = kvm_segment_from_gdt(gdt[1], 1);
    let data_seg = kvm_segment_from_gdt(gdt[2], 2);
    let tss_seg = kvm_segment_from_gdt(gdt[3], 3);

    sregs.cs = code_seg;
    sregs.ds = data_seg;
    sregs.es = data_seg;
    sregs.fs = data_seg;
    sregs.gs = data_seg;
    sregs.ss = data_seg;
    sregs.tr = tss_seg;

    sregs.gdt.base = BOOT_GDT_OFFSET;
    sregs.gdt.limit = (std::mem::size_of::<u64>() * BOOT_GDT_MAX - 1) as u16; // 31
    sregs.idt.base = BOOT_IDT_OFFSET;
    sregs.idt.limit = (std::mem::size_of::<u64>() - 1) as u16; // 7

    // 64-bit protected mode (Firecracker LinuxBoot): PE from segments, then
    // PG + cr3 + PAE + EFER.LME|LMA from the page-table setup.
    sregs.cr0 |= X86_CR0_PE | X86_CR0_PG;
    sregs.cr3 = PML4_START;
    sregs.cr4 |= X86_CR4_PAE;
    sregs.efer |= EFER_LME | EFER_LMA;

    vcpu.set_sregs(&sregs)?;
    Ok(())
}

/// `KVM_SET_REGS`: enter at `entry` with the tb-boot ABI — `rdi` = guest-phys
/// TbBootInfo (SysV arg0), `rsi` = 0, `rflags` = 0x2.
///
/// (Firecracker's LinuxBoot also sets rsp/rbp/rsi for the Linux zero-page ABI;
/// the TABOS kernel's `_tb_start` instead sets its own RSP and reads `rdi`, so
/// we leave rsp/rbp at 0 and place our info pointer in rdi.)
fn setup_regs(vcpu: &VcpuFd, entry: u64, boot_info_addr: u64) -> Result<(), VmmError> {
    let regs = kvm_regs {
        rflags: 0x0000_0000_0000_0002u64,
        rip: entry,
        rdi: boot_info_addr,
        rsi: 0,
        ..Default::default()
    };
    vcpu.set_regs(&regs)?;
    Ok(())
}

/// Present the host's supported CPUID to the guest (`KVM_SET_CPUID2`). The
/// soft-float TABOS kernel does not enable advertised SIMD features, but this
/// keeps any `cpuid` the guest issues well-defined rather than all-zero.
fn configure_cpuid(kvm: &Kvm, vcpu: &VcpuFd) -> Result<(), VmmError> {
    let cpuid = kvm.get_supported_cpuid(KVM_MAX_CPUID_ENTRIES as usize)?;
    vcpu.set_cpuid2(&cpuid)?;
    Ok(())
}

/// VM-level x86 setup: reserve KVM's real-mode TSS region (Firecracker always
/// calls `set_tss_address(0xfffbd000)`), unless guest RAM extends over it.
fn configure_vm(vm: &VmFd, mem: &GuestMemoryMmap) -> Result<(), VmmError> {
    if (mem.last_addr().raw_value() as usize) < KVM_TSS_ADDRESS {
        vm.set_tss_address(KVM_TSS_ADDRESS)?;
    }
    Ok(())
}

/// Full x86_64 boot configuration: VM TSS region, CPUID, boot structures in
/// guest RAM, then the long-mode sregs/regs. After this the vCPU is ready to run.
pub fn setup(
    kvm: &Kvm,
    vm: &VmFd,
    vcpu: &VcpuFd,
    mem: &GuestMemoryMmap,
    params: &BootParams,
) -> Result<(), VmmError> {
    let _: &[MemRegion] = params.mem_regions; // documents the seam input type
    configure_vm(vm, mem)?;
    configure_cpuid(kvm, vcpu)?;
    let boot_info_addr = write_system_memory(mem, params)?;
    setup_sregs(vcpu)?;
    setup_regs(vcpu, params.entry_point, boot_info_addr)?;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::memory::MemKind;
    use vm_memory::{Bytes, GuestAddress, GuestMemoryMmap};

    fn mem() -> GuestMemoryMmap {
        GuestMemoryMmap::from_ranges(&[(GuestAddress(0), 0x20_0000)]).unwrap()
    }

    // The exact qwords are asserted by Firecracker's own gdt.rs/regs.rs tests.
    #[test]
    fn gdt_entries_match_firecracker() {
        let g = gdt_table();
        assert_eq!(g[0], 0x0);
        assert_eq!(g[1], 0x00af_9b00_0000_ffff); // CODE
        assert_eq!(g[2], 0x00cf_9300_0000_ffff); // DATA
        assert_eq!(g[3], 0x008f_8b00_0000_ffff); // TSS
    }

    #[test]
    fn code_segment_decodes_to_long_mode() {
        let seg = kvm_segment_from_gdt(gdt_table()[1], 1);
        assert_eq!(seg.selector, 0x08);
        assert_eq!(seg.l, 1, "code segment must be 64-bit (L=1)");
        assert_eq!(seg.present, 1);
        assert_eq!(seg.dpl, 0);
        assert_eq!(seg.g, 1);
        assert_eq!(seg.limit, 0xffff_ffff);
        assert_eq!(seg.unusable, 0);
    }

    #[test]
    fn page_tables_identity_map_first_gib() {
        let gm = mem();
        setup_page_tables(&gm).unwrap();
        assert_eq!(gm.read_obj::<u64>(GuestAddress(PML4_START)).unwrap(), 0xa003);
        assert_eq!(gm.read_obj::<u64>(GuestAddress(PDPTE_START)).unwrap(), 0xb003);
        for i in 0..512u64 {
            let pde: u64 = gm.read_obj(GuestAddress(PDE_START + i * 8)).unwrap();
            assert_eq!(pde, (i << 21) | 0x83);
        }
    }

    #[test]
    fn gdt_written_to_guest_low_memory() {
        let gm = mem();
        write_gdt(&gm).unwrap();
        write_idt(&gm).unwrap();
        assert_eq!(gm.read_obj::<u64>(GuestAddress(BOOT_GDT_OFFSET)).unwrap(), 0x0);
        assert_eq!(
            gm.read_obj::<u64>(GuestAddress(BOOT_GDT_OFFSET + 8)).unwrap(),
            0x00af_9b00_0000_ffff
        );
        assert_eq!(gm.read_obj::<u64>(GuestAddress(BOOT_IDT_OFFSET)).unwrap(), 0x0);
    }

    #[test]
    fn boot_info_serialization_layout() {
        let b = serialize_boot_info(
            tb_boot::TB_BOOT_MAGIC,
            tb_boot::TB_BOOT_VERSION,
            0,
            TB_MEM_REGIONS_ADDR,
            2,
            TB_CMDLINE_ADDR,
            5,
            0x0010_0000,
        );
        assert_eq!(u64::from_le_bytes(b[0..8].try_into().unwrap()), tb_boot::TB_BOOT_MAGIC);
        assert_eq!(u32::from_le_bytes(b[8..12].try_into().unwrap()), tb_boot::TB_BOOT_VERSION);
        assert_eq!(u32::from_le_bytes(b[12..16].try_into().unwrap()), 0);
        assert_eq!(u64::from_le_bytes(b[16..24].try_into().unwrap()), TB_MEM_REGIONS_ADDR);
        assert_eq!(u64::from_le_bytes(b[24..32].try_into().unwrap()), 2);
        assert_eq!(u64::from_le_bytes(b[32..40].try_into().unwrap()), TB_CMDLINE_ADDR);
        assert_eq!(u64::from_le_bytes(b[40..48].try_into().unwrap()), 5);
        assert_eq!(u64::from_le_bytes(b[48..56].try_into().unwrap()), 0x0010_0000);
    }

    #[test]
    fn mem_region_serialization_layout() {
        let b = serialize_mem_region(0x1000, 0x4000, MemKind::Ram as u32);
        assert_eq!(u64::from_le_bytes(b[0..8].try_into().unwrap()), 0x1000);
        assert_eq!(u64::from_le_bytes(b[8..16].try_into().unwrap()), 0x4000);
        assert_eq!(u32::from_le_bytes(b[16..20].try_into().unwrap()), 1);
        assert_eq!(u32::from_le_bytes(b[20..24].try_into().unwrap()), 0);
    }

    #[test]
    fn writes_boot_block_and_validates_cmdline_bound() {
        let gm = mem();
        let regions = [MemRegion { base: 0, len: 0x20_0000, kind: MemKind::Ram }];
        let params = BootParams { entry_point: 0x0010_0000, mem_regions: &regions, cmdline: "ro" };
        let addr = write_system_memory(&gm, &params).unwrap();
        assert_eq!(addr, TB_BOOT_INFO_ADDR);
        // magic landed
        assert_eq!(gm.read_obj::<u64>(GuestAddress(TB_BOOT_INFO_ADDR)).unwrap(), tb_boot::TB_BOOT_MAGIC);
        // region landed
        assert_eq!(gm.read_obj::<u64>(GuestAddress(TB_MEM_REGIONS_ADDR)).unwrap(), 0);
        assert_eq!(gm.read_obj::<u64>(GuestAddress(TB_MEM_REGIONS_ADDR + 8)).unwrap(), 0x20_0000);

        // Over-long cmdline is rejected.
        let huge = "x".repeat((TB_LOWMEM_LIMIT - TB_CMDLINE_ADDR) as usize + 1);
        let bad = BootParams { entry_point: 0, mem_regions: &regions, cmdline: &huge };
        assert!(matches!(write_system_memory(&gm, &bad), Err(VmmError::Config(_))));
    }
}

//! The VM lifecycle and the `KVM_RUN` exit loop.
//!
//! [`Vmm::new`] wires KVM -> guest RAM -> kernel image -> vCPU -> devices ->
//! arch boot setup; [`Vmm::run`] drives `KVM_RUN`, dispatching serial PIO,
//! MMIO, and terminal exits (HLT/shutdown), with a wall-clock guard and an
//! exit budget so a hung guest cannot run forever.
//!
//! KVM exit-reason handling follows kvm-ioctls `VcpuExit` (docs.rs/kvm-ioctls):
//! `IoOut(port,&[u8])`, `IoIn(port,&mut[u8])`, `MmioRead`, `MmioWrite`, `Hlt`,
//! `Shutdown`, `SystemEvent`, `FailEntry(reason,cpu)`, `InternalError`.

use std::io;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

use kvm_bindings::KVM_API_VERSION;
use kvm_ioctls::{Kvm, VcpuExit, VcpuFd, VmFd};

use crate::arch::{self, BootParams};
use crate::cli::Config;
use crate::device::Bus;
use crate::error::VmmError;
use crate::loader;
use crate::memory::GuestRam;
use crate::serial::Serial;

/// COM1 base port + register span (16550 has 8 registers).
const COM1_BASE: u64 = 0x3f8;
const COM1_LEN: u64 = 8;

/// Upper bound on VM exits before we declare the guest hung. The M0-M4 boot
/// produces only a few thousand exits (serial bytes), so this is vast headroom.
const MAX_EXITS: u64 = 5_000_000;

/// Why the run loop stopped.
#[derive(Debug, Clone, Copy)]
pub enum StopReason {
    /// Guest executed `HLT` (the kernel halts after M4 — the clean stop).
    Halted,
    /// `KVM_EXIT_SHUTDOWN` (triple fault / reset).
    Shutdown,
    /// `KVM_EXIT_SYSTEM_EVENT` (e.g. PSCI/ACPI shutdown).
    SystemEvent(u32),
}

/// A configured, ready-to-run virtual machine.
///
/// Field order is the drop order: the vCPU drops first, then the VM, then guest
/// RAM (whose mmap must stay valid while the VM fd is open), then the Kvm handle.
pub struct Vmm {
    config: Config,
    pio_bus: Bus,
    mmio_bus: Bus,
    vcpu: VcpuFd,
    vm: VmFd,
    ram: GuestRam,
    _kvm: Kvm,
}

impl Vmm {
    /// Build the VM: open KVM, allocate + register guest RAM, load the kernel,
    /// create the vCPU, attach devices, and run the arch boot configuration.
    pub fn new(config: Config) -> Result<Self, VmmError> {
        let kvm = Kvm::new().map_err(VmmError::KvmInit)?;
        let api = kvm.get_api_version();
        if api != KVM_API_VERSION as i32 {
            return Err(VmmError::ApiVersion(api));
        }

        let vm = kvm.create_vm()?;

        // Guest RAM + KVM memslots.
        let ram = GuestRam::new(config.mem_bytes)?;
        ram.register_with_kvm(&vm)?;

        // Load the kernel ELF into guest RAM and resolve the 64-bit entry.
        let image = std::fs::read(&config.kernel_path)
            .map_err(|e| VmmError::KernelRead(config.kernel_path.clone(), e))?;
        let loaded = loader::load_kernel(&image, ram.inner())?;
        if config.print_exit {
            eprintln!(
                "tb-vmm: loaded kernel entry={:#x} (from {}), image_end={:#x}",
                loaded.entry,
                if loaded.entry_from_note { "TABOS note" } else { "e_entry fallback" },
                loaded.image_end
            );
            if !loaded.entry_from_note {
                eprintln!(
                    "tb-vmm: warning: no TABOS tb-boot note found; using e_entry. The kernel must \
                     expose a 64-bit entry via the TABOS ELF note for the tb-boot path."
                );
            }
        }

        let vcpu = vm.create_vcpu(0)?;

        // Devices: a 16550A UART on COM1 carrying guest output to stdout.
        let mut pio_bus = Bus::new();
        let mmio_bus = Bus::new();
        let serial = Arc::new(Mutex::new(Serial::new(Box::new(io::stdout()))));
        pio_bus.register(COM1_BASE, COM1_LEN, serial)?;

        // Arch boot configuration (boot structures + sregs/regs).
        let params = BootParams {
            entry_point: loaded.entry,
            mem_regions: ram.regions(),
            cmdline: &config.cmdline,
        };
        arch::setup(&kvm, &vm, &vcpu, ram.inner(), &params)?;

        Ok(Self {
            config,
            pio_bus,
            mmio_bus,
            vcpu,
            vm,
            ram,
            _kvm: kvm,
        })
    }

    /// Drive `KVM_RUN` until the guest halts/shuts down, or a guard fires.
    pub fn run(&mut self) -> Result<StopReason, VmmError> {
        let _ = &self.vm; // VM fd kept alive for the duration of the run
        let deadline = Instant::now() + Duration::from_secs(self.config.timeout_secs);
        let mut exits: u64 = 0;

        // The loop breaks with either a clean StopReason or an error sentinel.
        enum Outcome {
            Stop(StopReason),
            Timeout,
            ExitBudget,
            Fail { reason: u64, cpu: u32 },
            Internal,
            RunErr(kvm_ioctls::Error),
        }

        let outcome = loop {
            if Instant::now() >= deadline {
                break Outcome::Timeout;
            }
            exits += 1;
            if exits > MAX_EXITS {
                break Outcome::ExitBudget;
            }

            match self.vcpu.run() {
                Ok(exit) => match exit {
                    VcpuExit::IoIn(port, data) => self.pio_bus.read(port as u64, data),
                    VcpuExit::IoOut(port, data) => self.pio_bus.write(port as u64, data),
                    VcpuExit::MmioRead(addr, data) => self.mmio_bus.read(addr, data),
                    VcpuExit::MmioWrite(addr, data) => self.mmio_bus.write(addr, data),
                    VcpuExit::Hlt => break Outcome::Stop(StopReason::Halted),
                    VcpuExit::Shutdown => break Outcome::Stop(StopReason::Shutdown),
                    VcpuExit::SystemEvent(ev, _) => {
                        break Outcome::Stop(StopReason::SystemEvent(ev))
                    }
                    VcpuExit::FailEntry(reason, cpu) => break Outcome::Fail { reason, cpu },
                    VcpuExit::InternalError => break Outcome::Internal,
                    other => {
                        if self.config.print_exit {
                            eprintln!("tb-vmm: ignoring unhandled VM exit: {other:?}");
                        }
                    }
                },
                Err(e) => {
                    // EINTR is benign (a delivered signal); retry. Anything else
                    // is fatal for our single-shot boot.
                    if e.errno() == libc_eintr() {
                        continue;
                    }
                    break Outcome::RunErr(e);
                }
            }
        };

        // Post-loop: the vCPU borrow from the run() exit has ended, so we may
        // now read regs/sregs for diagnostics.
        match outcome {
            Outcome::Stop(reason) => Ok(reason),
            Outcome::Timeout => {
                self.dump_diagnostics("run guard (timeout)");
                Err(VmmError::Timeout { secs: self.config.timeout_secs })
            }
            Outcome::ExitBudget => {
                self.dump_diagnostics("exit budget exhausted");
                Err(VmmError::ExitBudget(MAX_EXITS))
            }
            Outcome::Fail { reason, cpu } => {
                self.dump_diagnostics("KVM_EXIT_FAIL_ENTRY");
                Err(VmmError::GuestFault { reason, cpu })
            }
            Outcome::Internal => {
                self.dump_diagnostics("KVM_EXIT_INTERNAL_ERROR");
                Err(VmmError::InternalError)
            }
            Outcome::RunErr(e) => {
                self.dump_diagnostics("KVM_RUN error");
                Err(VmmError::Kvm(e))
            }
        }
    }

    /// Best-effort dump of vCPU state to stderr for boot-failure triage.
    fn dump_diagnostics(&self, context: &str) {
        eprintln!("tb-vmm: vCPU diagnostics ({context}):");
        match self.vcpu.get_regs() {
            Ok(r) => eprintln!(
                "  rip={:#018x} rflags={:#x} rsp={:#018x} rdi={:#018x} rsi={:#018x}",
                r.rip, r.rflags, r.rsp, r.rdi, r.rsi
            ),
            Err(e) => eprintln!("  <get_regs failed: {e}>"),
        }
        match self.vcpu.get_sregs() {
            Ok(s) => eprintln!(
                "  cr0={:#x} cr3={:#018x} cr4={:#x} efer={:#x} cs.base={:#x} cs.l={} cs.sel={:#x}",
                s.cr0, s.cr3, s.cr4, s.efer, s.cs.base, s.cs.l, s.cs.selector
            ),
            Err(e) => eprintln!("  <get_sregs failed: {e}>"),
        }
    }
}

/// `EINTR` without pulling in the `libc` crate (kvm-ioctls already depends on
/// it transitively, but we keep our direct deps minimal).
fn libc_eintr() -> i32 {
    4
}

//! `tb-vmm` :: KVM layer — safe-ish `Vm` / `Vcpu` wrappers over `kvm-ioctls`.
//!
//! This is the ONLY place in `tb-vmm` that talks to `/dev/kvm`. `tb-vmm` is a
//! `std`, Linux-hosted binary in its **own audited-unsafe domain, explicitly
//! OUTSIDE** the framekernel's `#![forbid(unsafe_code)]` boundary
//! (docs/SOVEREIGNTY-ROADMAP.md §3). We still confine `unsafe` to exactly one
//! well-commented spot: [`Vm::set_user_memory_region`] (`KVM_SET_USER_MEMORY_REGION`
//! cannot be expressed safely because the kernel keeps a raw host pointer alive).
//!
//! Crate matrix (Firecracker baseline, verified): `kvm-ioctls 0.24.x`,
//! `kvm-bindings 0.14.x`.
//!
//! Sources (consulted, do not invent fields/constants):
//!  * kvm-ioctls API — <https://docs.rs/kvm-ioctls/0.24.0/kvm_ioctls/>
//!    (`Kvm::new`, `Kvm::create_vm`, `VmFd::set_user_memory_region` [unsafe],
//!    `VmFd::create_vcpu`, `VcpuFd::{get_sregs,set_sregs,get_regs,set_regs,
//!    set_fpu,run}`, `enum VcpuExit`).
//!  * KVM API — <https://docs.kernel.org/virt/kvm/api.html>
//!    (`kvm_userspace_memory_region` layout, `KVM_API_VERSION == 12`,
//!    `KVM_SET_TSS_ADDR`, `KVM_SET_IDENTITY_MAP_ADDR`, `KVM_CREATE_IRQCHIP`).

use kvm_bindings::{
    kvm_fpu, kvm_regs, kvm_sregs, kvm_userspace_memory_region, KVM_API_VERSION,
};
use kvm_ioctls::{Kvm, VcpuFd, VmFd};

// Re-export the FFI register structs + the exit enum so the rest of the crate
// (arch.rs builds sregs/regs; vmm.rs matches exits) binds to a single seam and
// never imports kvm-bindings / kvm-ioctls directly.
pub use kvm_bindings::{kvm_dtable, kvm_segment};
pub use kvm_ioctls::VcpuExit;

/// Errors raised by the KVM layer. Each variant names the failing ioctl so a
/// diagnostic carries the exact KVM operation that failed.
#[derive(Debug)]
pub enum KvmError {
    /// `open("/dev/kvm")` / `KVM_GET_API_VERSION` handshake failed.
    OpenKvm(kvm_ioctls::Error),
    /// `/dev/kvm` reports an API version other than [`KVM_API_VERSION`] (12).
    ApiVersion(i32),
    /// `KVM_CREATE_VM` failed.
    CreateVm(kvm_ioctls::Error),
    /// `KVM_CREATE_VCPU` failed.
    CreateVcpu(kvm_ioctls::Error),
    /// `KVM_SET_USER_MEMORY_REGION` failed.
    SetUserMemoryRegion(kvm_ioctls::Error),
    /// `KVM_CREATE_IRQCHIP` failed.
    CreateIrqChip(kvm_ioctls::Error),
    /// `KVM_SET_TSS_ADDR` failed.
    SetTssAddress(kvm_ioctls::Error),
    /// `KVM_SET_IDENTITY_MAP_ADDR` failed.
    SetIdentityMapAddress(kvm_ioctls::Error),
    /// `KVM_GET_SREGS` failed.
    GetSregs(kvm_ioctls::Error),
    /// `KVM_SET_SREGS` failed.
    SetSregs(kvm_ioctls::Error),
    /// `KVM_GET_REGS` failed.
    GetRegs(kvm_ioctls::Error),
    /// `KVM_SET_REGS` failed.
    SetRegs(kvm_ioctls::Error),
    /// `KVM_SET_FPU` failed.
    SetFpu(kvm_ioctls::Error),
    /// `KVM_RUN` failed.
    Run(kvm_ioctls::Error),
}

impl core::fmt::Display for KvmError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            KvmError::OpenKvm(e) => write!(f, "opening /dev/kvm failed: {e}"),
            KvmError::ApiVersion(v) => write!(
                f,
                "unexpected KVM API version {v} (tb-vmm requires {KVM_API_VERSION})"
            ),
            KvmError::CreateVm(e) => write!(f, "KVM_CREATE_VM failed: {e}"),
            KvmError::CreateVcpu(e) => write!(f, "KVM_CREATE_VCPU failed: {e}"),
            KvmError::SetUserMemoryRegion(e) => {
                write!(f, "KVM_SET_USER_MEMORY_REGION failed: {e}")
            }
            KvmError::CreateIrqChip(e) => write!(f, "KVM_CREATE_IRQCHIP failed: {e}"),
            KvmError::SetTssAddress(e) => write!(f, "KVM_SET_TSS_ADDR failed: {e}"),
            KvmError::SetIdentityMapAddress(e) => {
                write!(f, "KVM_SET_IDENTITY_MAP_ADDR failed: {e}")
            }
            KvmError::GetSregs(e) => write!(f, "KVM_GET_SREGS failed: {e}"),
            KvmError::SetSregs(e) => write!(f, "KVM_SET_SREGS failed: {e}"),
            KvmError::GetRegs(e) => write!(f, "KVM_GET_REGS failed: {e}"),
            KvmError::SetRegs(e) => write!(f, "KVM_SET_REGS failed: {e}"),
            KvmError::SetFpu(e) => write!(f, "KVM_SET_FPU failed: {e}"),
            KvmError::Run(e) => write!(f, "KVM_RUN failed: {e}"),
        }
    }
}

impl std::error::Error for KvmError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            KvmError::ApiVersion(_) => None,
            KvmError::OpenKvm(e)
            | KvmError::CreateVm(e)
            | KvmError::CreateVcpu(e)
            | KvmError::SetUserMemoryRegion(e)
            | KvmError::CreateIrqChip(e)
            | KvmError::SetTssAddress(e)
            | KvmError::SetIdentityMapAddress(e)
            | KvmError::GetSregs(e)
            | KvmError::SetSregs(e)
            | KvmError::GetRegs(e)
            | KvmError::SetRegs(e)
            | KvmError::SetFpu(e)
            | KvmError::Run(e) => Some(e),
        }
    }
}

/// A guest physical memory slot description handed to `KVM_SET_USER_MEMORY_REGION`.
///
/// The orchestrator's `memory` module produces one of these per `vm-memory`
/// region (see the integration note on `vmm.rs`); `userspace_addr` is the host
/// virtual address of the mmap backing the region.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MemorySlot {
    /// KVM memslot index (0, 1, ...). Must be unique per VM.
    pub slot: u32,
    /// Guest physical base address of the region.
    pub guest_phys_addr: u64,
    /// Region length in bytes (page-aligned).
    pub memory_size: u64,
    /// Host virtual address of the backing mmap.
    pub userspace_addr: u64,
}

/// Owner of a KVM VM file descriptor (and the parent `Kvm` handle).
pub struct Vm {
    kvm: Kvm,
    fd: VmFd,
}

impl Vm {
    /// Open `/dev/kvm`, validate the API version, and create a fresh VM.
    pub fn new() -> Result<Self, KvmError> {
        let kvm = Kvm::new().map_err(KvmError::OpenKvm)?;
        Self::from_kvm(kvm)
    }

    /// Create a VM from an already-opened [`Kvm`] (useful for tests that share
    /// a single `/dev/kvm` handle). Re-validates the API version.
    pub fn from_kvm(kvm: Kvm) -> Result<Self, KvmError> {
        let api = kvm.get_api_version();
        if api != KVM_API_VERSION as i32 {
            return Err(KvmError::ApiVersion(api));
        }
        let fd = kvm.create_vm().map_err(KvmError::CreateVm)?;
        Ok(Vm { kvm, fd })
    }

    /// Borrow the parent `/dev/kvm` handle (capability probing, vCPU mmap size).
    pub fn kvm(&self) -> &Kvm {
        &self.kvm
    }

    /// Borrow the raw `VmFd` for ioctls not yet wrapped here (e.g. ioeventfd,
    /// irqfd when virtio lands).
    pub fn fd(&self) -> &VmFd {
        &self.fd
    }

    /// Install one guest physical memory slot.
    ///
    /// (a) PRE: `userspace_addr` points at a live host mapping of at least
    ///     `memory_size` bytes; `slot` is unique; `[guest_phys_addr,
    ///     guest_phys_addr+memory_size)` does not overlap another slot.
    ///     POST: KVM serves guest accesses to that GPA range from the mapping.
    /// (b) ABI: thin wrapper over `VmFd::set_user_memory_region`, which is
    ///     `unsafe` in kvm-ioctls. `flags = 0` (no dirty-logging / read-only).
    /// (c) Tested by: the `vmm-boot` CI job (the whole tb-boot v0 path).
    ///
    /// # Safety
    /// `tb-vmm` is the audited-unsafe domain, but the obligation is real and
    /// non-local: the caller MUST keep the backing `GuestMemoryMmap` alive for
    /// **as long as this `Vm` (and any vCPU derived from it) lives**, because
    /// KVM dereferences `userspace_addr` on every guest memory fault. Dropping
    /// the mapping while the VM runs is undefined behaviour. The caller must
    /// also guarantee the slot does not overlap an existing one.
    pub unsafe fn set_user_memory_region(
        &self,
        slot: u32,
        guest_phys_addr: u64,
        memory_size: u64,
        userspace_addr: u64,
    ) -> Result<(), KvmError> {
        let region = kvm_userspace_memory_region {
            slot,
            flags: 0,
            guest_phys_addr,
            memory_size,
            userspace_addr,
        };
        // SAFETY: forwarded contract from this fn's `# Safety` section — the
        // caller owns the liveness + non-overlap guarantees; we only translate
        // the typed args into the FFI struct.
        unsafe {
            self.fd
                .set_user_memory_region(region)
                .map_err(KvmError::SetUserMemoryRegion)
        }
    }

    /// Convenience: install a [`MemorySlot`]. Same `# Safety` contract as
    /// [`Vm::set_user_memory_region`].
    ///
    /// # Safety
    /// See [`Vm::set_user_memory_region`].
    pub unsafe fn map_slot(&self, s: &MemorySlot) -> Result<(), KvmError> {
        // SAFETY: forwarded to set_user_memory_region's documented contract.
        unsafe {
            self.set_user_memory_region(
                s.slot,
                s.guest_phys_addr,
                s.memory_size,
                s.userspace_addr,
            )
        }
    }

    /// Create an in-kernel IRQ chip (`KVM_CREATE_IRQCHIP`).
    ///
    /// NOTE for the tb-boot v0 minimal boot path: do **NOT** call this. Without
    /// an in-kernel local APIC, `HLT` is delivered to userspace as
    /// `KVM_EXIT_HLT`, which is exactly how the kernel's post-M4 `cli; hlt`
    /// gives `tb-vmm` a clean stop (see `vmm.rs`). With an in-kernel irqchip,
    /// KVM would halt-poll in-kernel and never exit, hanging the run until the
    /// guard trips. Provided for completeness / future device work.
    pub fn create_irq_chip(&self) -> Result<(), KvmError> {
        self.fd.create_irq_chip().map_err(KvmError::CreateIrqChip)
    }

    /// `KVM_SET_TSS_ADDR`. Firecracker sets this to `0xfffb_d000`
    /// (`KVM_TSS_ADDRESS`, src/vmm/src/arch/x86_64/layout.rs). Only required on
    /// Intel when the guest is ever emulated in real/big-real mode; the tb-boot
    /// v0 path enters directly in long mode, so it is optional — but harmless
    /// and recommended for host portability.
    pub fn set_tss_address(&self, addr: usize) -> Result<(), KvmError> {
        self.fd.set_tss_address(addr).map_err(KvmError::SetTssAddress)
    }

    /// `KVM_SET_IDENTITY_MAP_ADDR` (Intel). Optional companion to
    /// [`Vm::set_tss_address`]; Firecracker uses `0xfffb_c000`.
    pub fn set_identity_map_address(&self, addr: u64) -> Result<(), KvmError> {
        self.fd
            .set_identity_map_address(addr)
            .map_err(KvmError::SetIdentityMapAddress)
    }

    /// Create vCPU `id` and map its `kvm_run` structure.
    pub fn create_vcpu(&self, id: u64) -> Result<Vcpu, KvmError> {
        let fd = self.fd.create_vcpu(id).map_err(KvmError::CreateVcpu)?;
        Ok(Vcpu { fd, id })
    }
}

/// Owner of a single vCPU file descriptor.
pub struct Vcpu {
    fd: VcpuFd,
    id: u64,
}

impl Vcpu {
    /// The vCPU index this object wraps.
    pub fn id(&self) -> u64 {
        self.id
    }

    /// Borrow the raw `VcpuFd` (for ioctls not yet wrapped, e.g. `set_cpuid2`).
    pub fn fd(&self) -> &VcpuFd {
        &self.fd
    }

    /// `KVM_GET_SREGS`.
    pub fn get_sregs(&self) -> Result<kvm_sregs, KvmError> {
        self.fd.get_sregs().map_err(KvmError::GetSregs)
    }

    /// `KVM_SET_SREGS`.
    pub fn set_sregs(&self, sregs: &kvm_sregs) -> Result<(), KvmError> {
        self.fd.set_sregs(sregs).map_err(KvmError::SetSregs)
    }

    /// `KVM_GET_REGS`.
    pub fn get_regs(&self) -> Result<kvm_regs, KvmError> {
        self.fd.get_regs().map_err(KvmError::GetRegs)
    }

    /// `KVM_SET_REGS`.
    pub fn set_regs(&self, regs: &kvm_regs) -> Result<(), KvmError> {
        self.fd.set_regs(regs).map_err(KvmError::SetRegs)
    }

    /// `KVM_SET_FPU`. Firecracker initialises `fcw = 0x37f`, `mxcsr = 0x1f80`
    /// (src/vmm/src/arch/x86_64/regs.rs `setup_fpu`).
    pub fn set_fpu(&self, fpu: &kvm_fpu) -> Result<(), KvmError> {
        self.fd.set_fpu(fpu).map_err(KvmError::SetFpu)
    }

    /// `KVM_RUN`. Returns the [`VcpuExit`], whose `&mut [u8]` payloads (for
    /// `IoIn` / `MmioRead`) borrow this vCPU's `kvm_run` mmap for the duration
    /// of the returned value — hence `&mut self`.
    pub fn run(&mut self) -> Result<VcpuExit<'_>, KvmError> {
        self.fd.run().map_err(KvmError::Run)
    }
}

