//! `tb-vmm` :: device bus — an extensible PIO/MMIO device registry.
//!
//! Design goal (docs/SOVEREIGNTY-ROADMAP.md §7): one console device is enough
//! for M0–M4 parity, but the *seam* must extend to a virtio-MMIO transport
//! later without reshaping the run loop. So the run loop ([`crate::vmm`]) only
//! ever calls [`DeviceBus::pio_read`] / `pio_write` / `mmio_read` / `mmio_write`;
//! everything behind those four methods is pluggable.
//!
//! Shape mirrors `rust-vmm`/Firecracker's `vm_device::Bus`: a range-keyed map
//! resolving an access address to `(device, offset_within_device)`. Devices are
//! held as `Arc<Mutex<dyn Device>>` so a future stdin-pump thread or virtio
//! queue worker can share the very same instance the vCPU thread drives.

use std::collections::BTreeMap;
use std::ops::Bound;
use std::sync::{Arc, Mutex};

pub mod serial;
pub use serial::Serial;

/// A memory-/port-mapped device. Object-safe so the bus can hold `dyn Device`.
///
/// `offset` is the access address **relative to the device's registered base**,
/// so a device never needs to know where it was placed. `data.len()` is the
/// access width KVM reported (1/2/4/8 for MMIO, 1/2/4 for PIO); string I/O
/// (`rep outsb`) arrives as a multi-byte buffer where each byte targets the
/// same `offset` — devices that care (e.g. a UART THR) stream it out.
pub trait Device: Send {
    /// Service a read of `data.len()` bytes at `offset`, filling `data`.
    fn read(&mut self, offset: u64, data: &mut [u8]);
    /// Service a write of `data` at `offset`.
    fn write(&mut self, offset: u64, data: &[u8]);
}

/// A device behind shared, interior-mutable ownership.
pub type SharedDevice = Arc<Mutex<dyn Device>>;

/// Errors from *registering* a device (access never errors — a miss is a
/// defined no-op, see [`Bus::read`]).
#[derive(Debug, PartialEq, Eq)]
pub enum BusError {
    /// Attempted to register a zero-length region.
    ZeroLength,
    /// `base + len` overflows the address space.
    Overflow { base: u64, len: u64 },
    /// The new region `[base, base+len)` overlaps an existing device whose
    /// region starts at `existing_base`.
    Overlap { base: u64, len: u64, existing_base: u64 },
}

impl core::fmt::Display for BusError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            BusError::ZeroLength => write!(f, "device region has zero length"),
            BusError::Overflow { base, len } => {
                write!(f, "device region [{base:#x}, +{len:#x}) overflows the address space")
            }
            BusError::Overlap {
                base,
                len,
                existing_base,
            } => write!(
                f,
                "device region [{base:#x}, +{len:#x}) overlaps existing device at {existing_base:#x}"
            ),
        }
    }
}

impl std::error::Error for BusError {}

struct BusEntry {
    len: u64,
    device: SharedDevice,
}

/// A single address space (PIO *or* MMIO) routing accesses to devices by range.
///
/// Lookup is `O(log n)`: find the greatest base `<= addr`, then bounds-check.
#[derive(Default)]
pub struct Bus {
    devices: BTreeMap<u64, BusEntry>,
}

impl Bus {
    /// An empty bus.
    pub fn new() -> Self {
        Bus {
            devices: BTreeMap::new(),
        }
    }

    /// Register `device` covering `[base, base+len)`. Rejects zero-length,
    /// overflowing, or overlapping regions so a misconfigured device map is a
    /// loud setup-time error, never a silent aliasing bug at run time.
    pub fn insert(&mut self, device: SharedDevice, base: u64, len: u64) -> Result<(), BusError> {
        if len == 0 {
            return Err(BusError::ZeroLength);
        }
        // Exclusive end; reject wrap-around (e.g. base near u64::MAX).
        let end = base.checked_add(len).ok_or(BusError::Overflow { base, len })?;

        // Predecessor: greatest existing base <= base. Overlaps iff its end > base.
        if let Some((&pbase, pe)) = self.devices.range(..=base).next_back() {
            if pbase.saturating_add(pe.len) > base {
                return Err(BusError::Overlap {
                    base,
                    len,
                    existing_base: pbase,
                });
            }
        }
        // Successor: smallest existing base strictly > base. Overlaps iff it
        // starts before our exclusive end. (An equal base is caught above.)
        if let Some((&nbase, _)) = self
            .devices
            .range((Bound::Excluded(base), Bound::Unbounded))
            .next()
        {
            if nbase < end {
                return Err(BusError::Overlap {
                    base,
                    len,
                    existing_base: nbase,
                });
            }
        }

        self.devices.insert(base, BusEntry { len, device });
        Ok(())
    }

    /// Resolve `addr` to `(offset_within_device, device)` if one covers it.
    fn resolve(&self, addr: u64) -> Option<(u64, &SharedDevice)> {
        let (&base, entry) = self.devices.range(..=addr).next_back()?;
        let offset = addr - base;
        if offset < entry.len {
            Some((offset, &entry.device))
        } else {
            None
        }
    }

    /// Read at `addr`. Returns `true` if a device handled it; on a miss the
    /// buffer is filled with `0xff` (open-bus convention) and `false` returned.
    pub fn read(&self, addr: u64, data: &mut [u8]) -> bool {
        match self.resolve(addr) {
            Some((offset, dev)) => {
                lock(dev).read(offset, data);
                true
            }
            None => {
                data.fill(0xff);
                false
            }
        }
    }

    /// Write at `addr`. Returns `true` if a device handled it; a miss is a
    /// no-op returning `false`.
    pub fn write(&self, addr: u64, data: &[u8]) -> bool {
        match self.resolve(addr) {
            Some((offset, dev)) => {
                lock(dev).write(offset, data);
                true
            }
            None => false,
        }
    }
}

/// Recover a poisoned lock instead of panicking: the device byte-state is just
/// data, and the run loop must not abort because some unrelated thread paniced
/// while holding the lock. (Single-threaded today; future-proof.)
fn lock(dev: &SharedDevice) -> std::sync::MutexGuard<'_, dyn Device> {
    dev.lock().unwrap_or_else(|poisoned| poisoned.into_inner())
}

/// The complete device model: a PIO space (x86 ports, `KVM_EXIT_IO`) and an
/// MMIO space (`KVM_EXIT_MMIO`). This is what the run loop owns.
#[derive(Default)]
pub struct DeviceBus {
    pio: Bus,
    mmio: Bus,
}

impl DeviceBus {
    /// An empty device model.
    pub fn new() -> Self {
        DeviceBus {
            pio: Bus::new(),
            mmio: Bus::new(),
        }
    }

    /// Register a port-mapped device (e.g. the 16550A UART at `0x3f8`, len 8).
    pub fn register_pio(
        &mut self,
        device: SharedDevice,
        base: u16,
        len: u16,
    ) -> Result<(), BusError> {
        self.pio.insert(device, u64::from(base), u64::from(len))
    }

    /// Register a memory-mapped device (future virtio-MMIO transports).
    pub fn register_mmio(
        &mut self,
        device: SharedDevice,
        base: u64,
        len: u64,
    ) -> Result<(), BusError> {
        self.mmio.insert(device, base, len)
    }

    /// Serve `KVM_EXIT_IO` IN.
    pub fn pio_read(&self, port: u16, data: &mut [u8]) -> bool {
        self.pio.read(u64::from(port), data)
    }

    /// Serve `KVM_EXIT_IO` OUT.
    pub fn pio_write(&self, port: u16, data: &[u8]) -> bool {
        self.pio.write(u64::from(port), data)
    }

    /// Serve `KVM_EXIT_MMIO` read.
    pub fn mmio_read(&self, addr: u64, data: &mut [u8]) -> bool {
        self.mmio.read(addr, data)
    }

    /// Serve `KVM_EXIT_MMIO` write.
    pub fn mmio_write(&self, addr: u64, data: &[u8]) -> bool {
        self.mmio.write(addr, data)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Records the last write and returns `offset` (low byte) on read, so a
    /// test can assert the bus handed it the correct *relative* offset.
    #[derive(Default)]
    struct Probe {
        last_offset: u64,
        last_write: Vec<u8>,
    }
    impl Device for Probe {
        fn read(&mut self, offset: u64, data: &mut [u8]) {
            self.last_offset = offset;
            for b in data.iter_mut() {
                *b = offset as u8;
            }
        }
        fn write(&mut self, offset: u64, data: &[u8]) {
            self.last_offset = offset;
            self.last_write = data.to_vec();
        }
    }

    fn probe() -> Arc<Mutex<Probe>> {
        Arc::new(Mutex::new(Probe::default()))
    }

    #[test]
    fn routes_to_relative_offset() {
        let mut bus = Bus::new();
        let dev = probe();
        bus.insert(dev.clone(), 0x3f8, 8).unwrap();

        let mut buf = [0u8; 1];
        assert!(bus.read(0x3fb, &mut buf)); // LCR == base+3
        assert_eq!(buf[0], 3);
        assert_eq!(dev.lock().unwrap().last_offset, 3);
    }

    #[test]
    fn miss_reads_open_bus_and_writes_are_noops() {
        let bus = Bus::new();
        let mut buf = [0u8; 4];
        assert!(!bus.read(0x1000, &mut buf));
        assert_eq!(buf, [0xff, 0xff, 0xff, 0xff]);
        assert!(!bus.write(0x1000, &[1, 2, 3, 4]));
    }

    #[test]
    fn rejects_overlap_in_both_directions() {
        let mut bus = Bus::new();
        bus.insert(probe(), 0x100, 0x10).unwrap();
        // starts inside the existing region
        assert_eq!(
            bus.insert(probe(), 0x108, 0x10),
            Err(BusError::Overlap {
                base: 0x108,
                len: 0x10,
                existing_base: 0x100,
            })
        );
        // ends inside the existing region
        assert_eq!(
            bus.insert(probe(), 0x0f8, 0x10),
            Err(BusError::Overlap {
                base: 0x0f8,
                len: 0x10,
                existing_base: 0x100,
            })
        );
        // exact-base duplicate
        assert!(matches!(
            bus.insert(probe(), 0x100, 0x4),
            Err(BusError::Overlap { .. })
        ));
        // adjacent, non-overlapping is fine
        assert!(bus.insert(probe(), 0x110, 0x10).is_ok());
    }

    #[test]
    fn rejects_zero_length_and_overflow() {
        let mut bus = Bus::new();
        assert_eq!(bus.insert(probe(), 0x10, 0), Err(BusError::ZeroLength));
        assert_eq!(
            bus.insert(probe(), u64::MAX, 2),
            Err(BusError::Overflow {
                base: u64::MAX,
                len: 2
            })
        );
    }

    #[test]
    fn pio_and_mmio_spaces_are_independent() {
        let mut model = DeviceBus::new();
        let pio_dev = probe();
        let mmio_dev = probe();
        // Same numeric base in the two distinct spaces must not collide.
        model.register_pio(pio_dev.clone(), 0x3f8, 8).unwrap();
        model.register_mmio(mmio_dev.clone(), 0x3f8, 8).unwrap();

        assert!(model.pio_write(0x3f9, &[0xaa]));
        assert!(model.mmio_write(0x3fa, &[0xbb]));
        assert_eq!(pio_dev.lock().unwrap().last_offset, 1);
        assert_eq!(mmio_dev.lock().unwrap().last_offset, 2);

        // A PIO port with no device is an open-bus miss, not an MMIO hit.
        let mut buf = [0u8; 1];
        assert!(!model.pio_read(0x2f8, &mut buf));
        assert_eq!(buf[0], 0xff);
    }
}

//! `tb-vmm` :: 16550A UART device — COM1 @ port `0x3f8`, output to a sink.
//!
//! This carries the guest kernel's serial output to `tb-vmm`'s chosen writer
//! (stdout in production) so CI can grep the milestone marker
//! `"M4: user/ring OK"`, exactly as the QEMU/PVH path does today
//! (scripts/run-x86_64.sh). It is the mirror image of the kernel-side driver in
//! `crates/tb-hal/src/arch/x86_64/serial.rs`, which drives COM1 with the
//! standard init sequence (IER=0, LCR.DLAB=1, DLL=1, LCR=0x03 8N1, FCR=0xC7,
//! MCR=0x0B) and TX-polls LSR bit 5 (THRE) — every one of those accesses is
//! serviced here.
//!
//! Why hand-rolled rather than `vm-superio::Serial`: a self-contained 16550A
//! keeps the register semantics as *pure, unit-testable logic* with no `EventFd`
//! interrupt-trigger or IRQ-routing dependency (none of which the polled boot
//! path needs). `vm-superio` remains a drop-in swap behind the [`Device`] trait
//! when interrupt-driven I/O is wanted.
//!
//! Register map (offset from base, the 16550 datasheet / OSDev "Serial Ports"):
//! ```text
//!   off  DLAB=0 read   DLAB=0 write   DLAB=1
//!   0    RBR           THR            DLL  (divisor low)
//!   1    IER           IER            DLM  (divisor high)
//!   2    IIR           FCR            IIR/FCR
//!   3    LCR           LCR            LCR  (bit 7 = DLAB)
//!   4    MCR           MCR            MCR  (bit 4 = LOOP)
//!   5    LSR (ro)      —              LSR
//!   6    MSR (ro)      —              MSR
//!   7    SCR           SCR            SCR  (scratch)
//! ```

use std::io::Write;

use super::Device;

// Register offsets from the UART base.
const REG_DATA: u64 = 0; // RBR / THR / DLL
const REG_IER_DLM: u64 = 1; // IER / DLM
const REG_IIR_FCR: u64 = 2; // IIR (r) / FCR (w)
const REG_LCR: u64 = 3;
const REG_MCR: u64 = 4;
const REG_LSR: u64 = 5;
const REG_MSR: u64 = 6;
const REG_SCR: u64 = 7;

// LCR bit 7 = Divisor Latch Access Bit.
const LCR_DLAB: u8 = 0x80;

// MCR bits.
const MCR_DTR: u8 = 0x01;
const MCR_RTS: u8 = 0x02;
const MCR_OUT1: u8 = 0x04;
const MCR_OUT2: u8 = 0x08;
const MCR_LOOP: u8 = 0x10;

// LSR bits.
const LSR_DR: u8 = 0x01; // Data Ready (RX byte available)
const LSR_THRE: u8 = 0x20; // TX Holding Register Empty
const LSR_TEMT: u8 = 0x40; // TX shift register also empty
/// LSR value when idle: we never buffer TX, so THRE|TEMT are always asserted.
const LSR_IDLE: u8 = LSR_THRE | LSR_TEMT;

// MSR bits (used in loopback to mirror MCR control lines).
const MSR_CTS: u8 = 0x10;
const MSR_DSR: u8 = 0x20;
const MSR_RI: u8 = 0x40;
const MSR_DCD: u8 = 0x80;

// IIR: bit0=1 means "no interrupt pending"; bits6-7 set when FIFOs enabled.
const IIR_NO_INT: u8 = 0x01;
const IIR_FIFO_ENABLED: u8 = 0xc0;
const FCR_ENABLE_FIFO: u8 = 0x01;

/// A 16550A UART writing transmitted bytes into the sink `W`.
pub struct Serial<W: Write> {
    ier: u8,
    fcr: u8,
    lcr: u8,
    mcr: u8,
    scr: u8,
    dll: u8,
    dlm: u8,
    /// Pending RX bytes the guest will read back via RBR (fed by
    /// [`Serial::enqueue_input`], or by loopback).
    rx: std::collections::VecDeque<u8>,
    out: W,
}

impl<W: Write> Serial<W> {
    /// A UART in its power-on reset state, transmitting into `out`.
    pub fn new(out: W) -> Self {
        Serial {
            ier: 0,
            fcr: 0,
            lcr: 0,
            mcr: 0,
            scr: 0,
            dll: 0,
            dlm: 0,
            rx: std::collections::VecDeque::new(),
            out,
        }
    }

    /// Feed bytes the guest will see as received input (RBR / LSR.DR). A stdin
    /// pump thread holding a typed `Arc<Mutex<Serial<_>>>` clone calls this.
    pub fn enqueue_input(&mut self, bytes: &[u8]) {
        self.rx.extend(bytes.iter().copied());
    }

    /// Borrow the output sink (tests assert on the captured bytes).
    pub fn writer(&self) -> &W {
        &self.out
    }

    fn dlab(&self) -> bool {
        self.lcr & LCR_DLAB != 0
    }

    fn loopback(&self) -> bool {
        self.mcr & MCR_LOOP != 0
    }

    /// Current Line Status Register value.
    fn lsr(&self) -> u8 {
        let mut v = LSR_IDLE;
        if !self.rx.is_empty() {
            v |= LSR_DR;
        }
        v
    }

    /// Modem Status Register: in loopback the four MCR control outputs are wired
    /// to the four MSR inputs (DTR->DSR, RTS->CTS, OUT1->RI, OUT2->DCD).
    fn msr(&self) -> u8 {
        if !self.loopback() {
            return 0;
        }
        let mut v = 0;
        if self.mcr & MCR_DTR != 0 {
            v |= MSR_DSR;
        }
        if self.mcr & MCR_RTS != 0 {
            v |= MSR_CTS;
        }
        if self.mcr & MCR_OUT1 != 0 {
            v |= MSR_RI;
        }
        if self.mcr & MCR_OUT2 != 0 {
            v |= MSR_DCD;
        }
        v
    }

    /// Transmit one byte: in loopback it returns as RX; otherwise it streams to
    /// the sink and is flushed so a marker without a trailing newline is still
    /// observed promptly by CI.
    fn transmit(&mut self, byte: u8) {
        if self.loopback() {
            self.rx.push_back(byte);
            return;
        }
        // Best-effort: a closed stdout (broken pipe) must not abort the VM run.
        let _ = self.out.write_all(&[byte]);
        let _ = self.out.flush();
    }

    /// Pure write of one register. The bus-facing [`Device::write`] applies this
    /// per byte (so `rep outsb` to THR streams a whole buffer out).
    fn write_reg(&mut self, offset: u64, value: u8) {
        match offset {
            REG_DATA => {
                if self.dlab() {
                    self.dll = value;
                } else {
                    self.transmit(value);
                }
            }
            REG_IER_DLM => {
                if self.dlab() {
                    self.dlm = value;
                } else {
                    self.ier = value;
                }
            }
            REG_IIR_FCR => self.fcr = value, // write side is FCR
            REG_LCR => self.lcr = value,
            REG_MCR => self.mcr = value,
            // LSR/MSR are read-only; writes are ignored by real hardware.
            REG_LSR | REG_MSR => {}
            REG_SCR => self.scr = value,
            _ => {}
        }
    }

    /// Pure read of one register.
    fn read_reg(&mut self, offset: u64) -> u8 {
        match offset {
            REG_DATA => {
                if self.dlab() {
                    self.dll
                } else {
                    self.rx.pop_front().unwrap_or(0)
                }
            }
            REG_IER_DLM => {
                if self.dlab() {
                    self.dlm
                } else {
                    self.ier
                }
            }
            REG_IIR_FCR => {
                if self.fcr & FCR_ENABLE_FIFO != 0 {
                    IIR_NO_INT | IIR_FIFO_ENABLED
                } else {
                    IIR_NO_INT
                }
            }
            REG_LCR => self.lcr,
            REG_MCR => self.mcr,
            REG_LSR => self.lsr(),
            REG_MSR => self.msr(),
            REG_SCR => self.scr,
            _ => 0,
        }
    }
}

impl Serial<std::io::Stdout> {
    /// The production UART: transmits guest serial output to `tb-vmm`'s stdout.
    pub fn stdout() -> Self {
        Serial::new(std::io::stdout())
    }
}

impl<W: Write + Send> Device for Serial<W> {
    fn read(&mut self, offset: u64, data: &mut [u8]) {
        for b in data.iter_mut() {
            *b = self.read_reg(offset);
        }
    }

    fn write(&mut self, offset: u64, data: &[u8]) {
        for &b in data {
            self.write_reg(offset, b);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn uart() -> Serial<Vec<u8>> {
        Serial::new(Vec::new())
    }

    #[test]
    fn thr_streams_bytes_to_sink() {
        let mut s = uart();
        s.write(REG_DATA, b"hi"); // two THR writes
        assert_eq!(s.writer().as_slice(), b"hi");
    }

    #[test]
    fn matches_kernel_init_sequence_then_emits() {
        // Replays crates/tb-hal/src/arch/x86_64/serial.rs::serial_init verbatim,
        // then a write, proving the divisor-latch dance leaves TX working.
        let mut s = uart();
        s.write(REG_IER_DLM, &[0x00]); // IER = 0
        s.write(REG_LCR, &[0x80]); // DLAB = 1
        s.write(REG_DATA, &[0x01]); // DLL = 1   (115200 baud)
        s.write(REG_IER_DLM, &[0x00]); // DLM = 0
        s.write(REG_LCR, &[0x03]); // DLAB = 0, 8N1
        s.write(REG_IIR_FCR, &[0xc7]); // FCR: FIFO on
        s.write(REG_MCR, &[0x0b]); // DTR|RTS|OUT2 (no loopback)
        assert!(s.writer().is_empty(), "init must not emit data bytes");

        s.write(REG_DATA, b"X");
        assert_eq!(s.writer().as_slice(), b"X");
    }

    #[test]
    fn lsr_reports_thre_always_and_dr_on_input() {
        let mut s = uart();
        let mut b = [0u8; 1];
        s.read(REG_LSR, &mut b);
        assert_eq!(b[0], LSR_THRE | LSR_TEMT); // idle: ready to transmit, no RX

        s.enqueue_input(b"q");
        s.read(REG_LSR, &mut b);
        assert_eq!(b[0], LSR_THRE | LSR_TEMT | LSR_DR);

        s.read(REG_DATA, &mut b); // consume RBR
        assert_eq!(b[0], b'q');
        s.read(REG_LSR, &mut b);
        assert_eq!(b[0], LSR_THRE | LSR_TEMT); // DR clears
    }

    #[test]
    fn dlab_exposes_divisor_latches() {
        let mut s = uart();
        let mut b = [0u8; 1];
        s.write(REG_LCR, &[LCR_DLAB]);
        s.write(REG_DATA, &[0x03]); // DLL
        s.write(REG_IER_DLM, &[0x00]); // DLM
        s.read(REG_DATA, &mut b);
        assert_eq!(b[0], 0x03); // reads DLL, not RBR
        s.read(REG_IER_DLM, &mut b);
        assert_eq!(b[0], 0x00); // reads DLM, not IER

        s.write(REG_LCR, &[0x03]); // clear DLAB
        s.write(REG_DATA, b"A");
        assert_eq!(s.writer().as_slice(), b"A"); // now THR again
    }

    #[test]
    fn scratch_register_round_trips() {
        let mut s = uart();
        let mut b = [0u8; 1];
        s.write(REG_SCR, &[0x5a]);
        s.read(REG_SCR, &mut b);
        assert_eq!(b[0], 0x5a);
    }

    #[test]
    fn loopback_routes_thr_to_rbr_and_mirrors_modem_lines() {
        let mut s = uart();
        let mut b = [0u8; 1];
        s.write(REG_MCR, &[MCR_LOOP | MCR_DTR | MCR_RTS]);

        s.write(REG_DATA, b"Z"); // loops back instead of emitting
        assert!(s.writer().is_empty());
        s.read(REG_LSR, &mut b);
        assert_eq!(b[0] & LSR_DR, LSR_DR);
        s.read(REG_DATA, &mut b);
        assert_eq!(b[0], b'Z');

        s.read(REG_MSR, &mut b); // DTR->DSR, RTS->CTS
        assert_eq!(b[0], MSR_DSR | MSR_CTS);
    }
}

//! `tb-vmm` :: the `KVM_RUN` loop — `tb-boot v0`'s machine driver.
//!
//! After the orchestrator has mapped guest RAM, loaded the kernel ELF, written
//! the boot info + page tables + GDT, and configured the vCPU's sregs/regs for
//! direct 64-bit long-mode entry (arch module, mirroring Firecracker
//! src/vmm/src/arch/x86_64/regs.rs), this loop runs the guest and services its
//! VM exits against the [`DeviceBus`].
//!
//! Exit policy (KVM API <https://docs.kernel.org/virt/kvm/api.html>,
//! kvm-ioctls `enum VcpuExit`):
//!  * `KVM_EXIT_IO`             -> PIO read/write on the device bus (serial).
//!  * `KVM_EXIT_MMIO`           -> MMIO read/write on the device bus.
//!  * `KVM_EXIT_HLT`            -> clean stop: the kernel `cli; hlt`s after the
//!                                M4 marker (kernel/src/main.rs). Delivered to
//!                                userspace because we run with NO in-kernel
//!                                irqchip (see kvm.rs::Vm::create_irq_chip).
//!  * `KVM_EXIT_SHUTDOWN` /
//!    `KVM_EXIT_SYSTEM_EVENT`   -> stop (triple-fault / PSCI-style reset).
//!  * `KVM_EXIT_FAIL_ENTRY` /
//!    `KVM_EXIT_INTERNAL_ERROR` -> dump diagnostics (exit reason + rip + sregs)
//!                                to STDERR and fail. (stdout is reserved for
//!                                guest serial so CI can grep the marker.)
//!
//! Infinite-run guard: a `max_exits` counter and an optional wall-clock
//! deadline bound the run so a wedged guest (e.g. a tight MMIO fault loop or a
//! never-halting kernel) cannot spin forever.

use std::time::{Duration, Instant};

use kvm_bindings::{
    KVM_SYSTEM_EVENT_CRASH, KVM_SYSTEM_EVENT_RESET, KVM_SYSTEM_EVENT_SHUTDOWN,
};

use crate::devices::DeviceBus;
use crate::kvm::{KvmError, Vcpu, VcpuExit};

/// Run-loop configuration (sourced from the CLI: `--print-exit`, guard knobs).
#[derive(Clone, Debug)]
pub struct RunConfig {
    /// Log every VM exit (reason + a one-line state) to stderr.
    pub print_exit: bool,
    /// Maximum number of VM exits before the guard trips (`0` = unbounded —
    /// rely on `timeout`).
    pub max_exits: u64,
    /// Wall-clock budget for the whole run (`None` = unbounded).
    pub timeout: Option<Duration>,
}

impl Default for RunConfig {
    fn default() -> Self {
        // A wedged guest cannot run forever even with default knobs.
        RunConfig {
            print_exit: false,
            max_exits: 0,
            timeout: Some(Duration::from_secs(30)),
        }
    }
}

/// How a run ended (clean outcomes).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum VmExit {
    /// `KVM_EXIT_HLT` — the expected clean stop after the kernel's M4 marker.
    Halted,
    /// `KVM_EXIT_SHUTDOWN` or a SYSTEM_EVENT shutdown/crash.
    Shutdown,
    /// A SYSTEM_EVENT reset request.
    Reset,
    /// The infinite-run guard fired after `exits` VM exits.
    GuardTripped { exits: u64 },
}

impl VmExit {
    /// `true` for outcomes that are a normal, non-error end of the VM.
    pub fn is_clean(&self) -> bool {
        matches!(self, VmExit::Halted | VmExit::Shutdown | VmExit::Reset)
    }
}

/// A run that ended in failure.
#[derive(Debug)]
pub enum RunError {
    /// A `KVM_RUN` (or a diagnostic ioctl) failed.
    Kvm(KvmError),
    /// `KVM_EXIT_FAIL_ENTRY`: hardware refused to enter the guest. Carries the
    /// `hardware_entry_failure_reason` and the cpu index from kvm-ioctls.
    FailedEntry { reason: u64, cpu: u32 },
    /// `KVM_EXIT_INTERNAL_ERROR`: KVM hit an internal/emulation error.
    InternalError,
    /// An exit reason this loop does not handle was observed (the formatted
    /// `VcpuExit` is captured for the diagnostic).
    Unexpected(String),
}

impl From<KvmError> for RunError {
    fn from(e: KvmError) -> Self {
        RunError::Kvm(e)
    }
}

impl core::fmt::Display for RunError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            RunError::Kvm(e) => write!(f, "{e}"),
            RunError::FailedEntry { reason, cpu } => write!(
                f,
                "KVM_EXIT_FAIL_ENTRY: hardware_entry_failure_reason={reason:#x} on cpu {cpu}"
            ),
            RunError::InternalError => write!(f, "KVM_EXIT_INTERNAL_ERROR"),
            RunError::Unexpected(s) => write!(f, "unhandled VM exit: {s}"),
        }
    }
}

impl std::error::Error for RunError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            RunError::Kvm(e) => Some(e),
            _ => None,
        }
    }
}

/// The infinite-run guard. Extracted so its pure logic is unit-testable without
/// a real vCPU.
struct RunGuard {
    max_exits: u64,
    exits: u64,
    deadline: Option<Instant>,
}

impl RunGuard {
    fn new(max_exits: u64, timeout: Option<Duration>) -> Self {
        RunGuard {
            max_exits,
            exits: 0,
            deadline: timeout.map(|d| Instant::now() + d),
        }
    }

    /// Account for one VM exit. Returns `true` if a limit was reached and the
    /// run must stop.
    fn tick(&mut self) -> bool {
        self.exits += 1;
        if self.max_exits != 0 && self.exits > self.max_exits {
            return true;
        }
        if let Some(dl) = self.deadline {
            if Instant::now() >= dl {
                return true;
            }
        }
        false
    }
}

/// What a single serviced VM exit tells the loop to do next. Owned (no borrow
/// of the vCPU), so diagnostics that re-read vCPU state can run *after* the
/// `VcpuExit` borrow ends.
enum Step {
    Continue,
    Done(VmExit),
    SystemEvent(u32),
    FailEntry { reason: u64, cpu: u32 },
    InternalError,
    Unexpected(String),
}

/// The machine: a configured vCPU + its device model + run policy.
pub struct Vmm {
    vcpu: Vcpu,
    bus: DeviceBus,
    config: RunConfig,
}

impl Vmm {
    /// Assemble a runnable VM from an already-configured vCPU and device bus.
    pub fn new(vcpu: Vcpu, bus: DeviceBus, config: RunConfig) -> Self {
        Vmm { vcpu, bus, config }
    }

    /// Borrow the device bus (e.g. to register more devices before `run`).
    pub fn bus_mut(&mut self) -> &mut DeviceBus {
        &mut self.bus
    }

    /// Drive the guest until it stops, fails, or the guard trips.
    pub fn run(&mut self) -> Result<VmExit, RunError> {
        let mut guard = RunGuard::new(self.config.max_exits, self.config.timeout);

        loop {
            if guard.tick() {
                self.dump_state("infinite-run guard tripped");
                return Ok(VmExit::GuardTripped { exits: guard.exits });
            }

            // Lower the (vCPU-borrowing) VcpuExit into an owned `Step`. Device
            // I/O — the only thing that needs the exit's `&mut [u8]` payload —
            // is fully serviced inside this match; nothing here touches the
            // vCPU again, so the borrow is released at the match's end.
            let step = match self.vcpu.run() {
                Ok(VcpuExit::IoOut(port, data)) => {
                    if self.config.print_exit {
                        eprintln!("[tb-vmm] IO  out port={port:#06x} len={}", data.len());
                    }
                    self.bus.pio_write(port, data);
                    Step::Continue
                }
                Ok(VcpuExit::IoIn(port, data)) => {
                    if self.config.print_exit {
                        eprintln!("[tb-vmm] IO  in  port={port:#06x} len={}", data.len());
                    }
                    self.bus.pio_read(port, data);
                    Step::Continue
                }
                Ok(VcpuExit::MmioWrite(addr, data)) => {
                    if self.config.print_exit {
                        eprintln!("[tb-vmm] MMIO wr  addr={addr:#x} len={}", data.len());
                    }
                    self.bus.mmio_write(addr, data);
                    Step::Continue
                }
                Ok(VcpuExit::MmioRead(addr, data)) => {
                    if self.config.print_exit {
                        eprintln!("[tb-vmm] MMIO rd  addr={addr:#x} len={}", data.len());
                    }
                    self.bus.mmio_read(addr, data);
                    Step::Continue
                }
                Ok(VcpuExit::Hlt) => Step::Done(VmExit::Halted),
                Ok(VcpuExit::Shutdown) => Step::Done(VmExit::Shutdown),
                Ok(VcpuExit::SystemEvent(event_type, _flags)) => Step::SystemEvent(event_type),
                Ok(VcpuExit::FailEntry(reason, cpu)) => Step::FailEntry { reason, cpu },
                Ok(VcpuExit::InternalError) => Step::InternalError,
                // Capture an unhandled reason by value (Debug-format consumes
                // the borrow, yielding an owned String).
                Ok(other) => Step::Unexpected(format!("{other:?}")),
                Err(e) => return Err(RunError::Kvm(e)),
            };

            match step {
                Step::Continue => {}
                Step::Done(exit) => return Ok(exit),
                Step::SystemEvent(event_type) => {
                    return Ok(self.classify_system_event(event_type));
                }
                Step::FailEntry { reason, cpu } => {
                    eprintln!(
                        "[tb-vmm] KVM_EXIT_FAIL_ENTRY: reason={reason:#x} cpu={cpu}"
                    );
                    self.dump_state("KVM_EXIT_FAIL_ENTRY");
                    return Err(RunError::FailedEntry { reason, cpu });
                }
                Step::InternalError => {
                    eprintln!("[tb-vmm] KVM_EXIT_INTERNAL_ERROR");
                    self.dump_state("KVM_EXIT_INTERNAL_ERROR");
                    return Err(RunError::InternalError);
                }
                Step::Unexpected(desc) => {
                    eprintln!("[tb-vmm] unhandled VM exit: {desc}");
                    self.dump_state("unhandled exit");
                    return Err(RunError::Unexpected(desc));
                }
            }
        }
    }

    /// Map a `KVM_EXIT_SYSTEM_EVENT` type to a clean outcome.
    fn classify_system_event(&self, event_type: u32) -> VmExit {
        if event_type == KVM_SYSTEM_EVENT_RESET {
            if self.config.print_exit {
                eprintln!("[tb-vmm] SYSTEM_EVENT reset");
            }
            VmExit::Reset
        } else {
            // SHUTDOWN / CRASH (and any future variant) -> stop.
            if self.config.print_exit {
                let what = match event_type {
                    KVM_SYSTEM_EVENT_SHUTDOWN => "shutdown",
                    KVM_SYSTEM_EVENT_CRASH => "crash",
                    _ => "other",
                };
                eprintln!("[tb-vmm] SYSTEM_EVENT {what} (type={event_type})");
            }
            VmExit::Shutdown
        }
    }

    /// Dump vCPU diagnostics to STDERR: instruction pointer, stack, flags, and
    /// the long-mode control state (cs/cr0/cr3/cr4/efer) — enough to tell a
    /// bad GDT/page-table/EFER setup apart from a guest fault. Best-effort: a
    /// failed diagnostic ioctl is itself reported, never panicked on.
    fn dump_state(&self, label: &str) {
        eprintln!("[tb-vmm] vm-exit diagnostics: {label}");
        match self.vcpu.get_regs() {
            Ok(r) => eprintln!(
                "  rip={:#018x} rsp={:#018x} rflags={:#x} rax={:#x} rdi={:#x} rsi={:#x}",
                r.rip, r.rsp, r.rflags, r.rax, r.rdi, r.rsi
            ),
            Err(e) => eprintln!("  <KVM_GET_REGS failed: {e}>"),
        }
        match self.vcpu.get_sregs() {
            Ok(s) => {
                eprintln!(
                    "  cs.sel={:#06x} cs.base={:#x} cs.limit={:#x} cs.l={} cs.db={}",
                    s.cs.selector, s.cs.base, s.cs.limit, s.cs.l, s.cs.db
                );
                eprintln!(
                    "  cr0={:#x} cr3={:#x} cr4={:#x} efer={:#x}",
                    s.cr0, s.cr3, s.cr4, s.efer
                );
            }
            Err(e) => eprintln!("  <KVM_GET_SREGS failed: {e}>"),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn guard_trips_after_max_exits() {
        let mut g = RunGuard::new(3, None);
        assert!(!g.tick()); // 1
        assert!(!g.tick()); // 2
        assert!(!g.tick()); // 3
        assert!(g.tick()); // 4 > 3 -> trip
        assert_eq!(g.exits, 4);
    }

    #[test]
    fn zero_max_exits_means_unbounded_by_count() {
        let mut g = RunGuard::new(0, None);
        for _ in 0..10_000 {
            assert!(!g.tick());
        }
    }

    #[test]
    fn zero_timeout_trips_immediately() {
        let mut g = RunGuard::new(0, Some(Duration::ZERO));
        assert!(g.tick());
    }

    #[test]
    fn vmexit_clean_classification() {
        assert!(VmExit::Halted.is_clean());
        assert!(VmExit::Shutdown.is_clean());
        assert!(VmExit::Reset.is_clean());
        assert!(!VmExit::GuardTripped { exits: 5 }.is_clean());
    }

    #[test]
    fn run_error_display_is_diagnostic() {
        let e = RunError::FailedEntry {
            reason: 0x8,
            cpu: 0,
        };
        assert!(format!("{e}").contains("FAIL_ENTRY"));
        assert!(format!("{e}").contains("0x8"));
    }
}

//! x86_64 PVH bootstrap: the A0 32->64 trampoline + the A1 `_start` entry.
//!
//! **Bootstrap-only (M0).** Per KERNEL-FOUNDATION-SPEC §2/§3 (unit A0) the
//! 32->64 trampoline is *deleted* once `tb-vmm` / `tb-boot v0` enters directly
//! in 64-bit long mode. This is the ONLY x86_64 boot assembly in TABOS.
//!
//! Boot contract (verified facts — obey exactly):
//!  * PVH "x86/HVM direct boot ABI": QEMU `-kernel` and Firecracker select PVH
//!    via the `XEN_ELFNOTE_PHYS32_ENTRY` ELF note (type **18**, name **"Xen"**,
//!    desc = 32-bit physical entry point). The note must sit in a `PT_NOTE`
//!    phdr (see kernel/linker/x86_64.ld).
//!      - https://xenbits.xen.org/docs/unstable/misc/pvh.html
//!      - xen/include/public/elfnote.h  (`#define XEN_ELFNOTE_PHYS32_ENTRY 18`)
//!      - note byte layout cross-checked vs Google's
//!        cloud-hypervisor/rust-hypervisor-firmware `src/pvh.rs`.
//!  * On entry the vCPU is in **32-bit protected mode, paging OFF**, with
//!    `cr0 = PE|ET` (all other writable bits clear), `cr4 = 0`, flat 4 GiB
//!    cs/ds/es/ss, and **`%ebx` -> `hvm_start_info`** (pvh.html).
//!  * `hvm_start_info` lives below 4 GiB; magic `0x336ec578` ("xEn3").
//!    - xen/include/public/arch-x86/hvm/start_info.h.
//!
//! The kernel image is loaded at 1 MiB (0x0010_0000); serial is legacy 16550
//! COM1 @ I/O port 0x3F8 (see serial.rs).

use core::arch::global_asm;

global_asm!(
r#"
// ===========================================================================
// PVH ELF note: XEN_ELFNOTE_PHYS32_ENTRY (type 18, name "Xen")
// (a) PRE: linked into a PT_NOTE phdr. POST: QEMU/Firecracker read `desc` and
//     enter at `_start` in 32-bit protected mode, paging off, ebx->start_info.
// (b) ABI: pure data; namesz=4 ("Xen\0"), descsz=4 (.long entry), type=18;
//     4-byte aligned (QEMU mis-pads notes when alignment != 4).
// (c) Tested by: scripts/run-x86_64.sh (the whole PVH boot path under QEMU).
// ===========================================================================
.section .note.Xen, "a", @note
.align 4
.long   4                       // n_namesz = sizeof("Xen\0")
.long   4                       // n_descsz = sizeof(.long entry)
.long   18                      // n_type   = XEN_ELFNOTE_PHYS32_ENTRY
.asciz  "Xen"                    // n_name   (4 bytes incl NUL; already aligned)
.long   _start                  // n_desc   = 32-bit physical entry point

// ---------------------------------------------------------------------------
// Boot GDT: flat, with a 64-bit code segment, used for the far return into
// long mode. The PVH ABI states the OS sets up its own GDT.
// ---------------------------------------------------------------------------
.section .rodata
.align 8
__boot_gdt64:
    .quad 0x0000000000000000    // 0x00 null
    .quad 0x00209A0000000000    // 0x08 64-bit code (L=1,P=1,DPL=0,exec/read)
    .quad 0x0000920000000000    // 0x10 data        (P=1,DPL=0,read/write)
__boot_gdt64_end:
.align 8
__boot_gdt64_ptr:
    .short __boot_gdt64_end - __boot_gdt64 - 1
    .long  __boot_gdt64         // 32-bit base: read by the 32-bit `lgdt`

// ---------------------------------------------------------------------------
// Boot scratch (NOBITS). Placed by the linker BEFORE __bss_start so the
// .bss-clear never wipes the live page tables. CR3 needs 4 KiB alignment.
// ---------------------------------------------------------------------------
.section .boot.pagetables, "aw", @nobits
.align 4096
__boot_pml4: .skip 4096
__boot_pdpt: .skip 4096
__boot_pd:   .skip 4096

.section .boot.stack, "aw", @nobits
.align 16
__boot_stack_bottom: .skip 0x10000     // 64 KiB boot stack
__boot_stack_top:

// ===========================================================================
// A1 `_start` (32-bit PVH entry) + A0 32->64 trampoline.
// (a) PRE: 32-bit protected mode, paging OFF, cr0=PE|ET, cr4=0, flat segments,
//     ebx->hvm_start_info. POST: 64-bit long mode, identity map [0,1GiB),
//     .bss zeroed, rsp on boot stack (16-aligned), rdi=hvm_start_info, then
//     `call rust_main` (rust_main is `-> !`).
// (b) ABI: SysV/x86_64. Builds its own GDT/CR3/EFER.LME/CR0.PG; clobbers all
//     GPRs; preserves ebx until it is moved into rdi (arg0) just before the
//     call; aligns rsp to 16 before `call` (callee sees rsp%16==8).
// (c) Tested by: scripts/run-x86_64.sh (asserts "hello from rust_main\n").
// ===========================================================================
.section .text._start, "ax", @progbits
.code32
.global _start
_start:
    cli
    cld
    lea     esp, [__boot_stack_top]     // 32-bit stack for the far return

    // Zero PML4+PDPT+PD (3 * 4096 bytes) so no stale entry is ever "present".
    lea     edi, [__boot_pml4]
    xor     eax, eax
    mov     ecx, 3072                   // (4096*3)/4 dwords
    rep     stosd

    // PML4[0] = &PDPT | PRESENT|WRITE   (high dword stays 0 from the zeroing)
    lea     edi, [__boot_pml4]
    lea     eax, [__boot_pdpt]
    or      eax, 0x3
    mov     [edi], eax

    // PDPT[0] = &PD | PRESENT|WRITE
    lea     edi, [__boot_pdpt]
    lea     eax, [__boot_pd]
    or      eax, 0x3
    mov     [edi], eax

    // PD[i] = (i * 2 MiB) | PRESENT|WRITE|PS  ->  identity-map [0, 1 GiB)
    lea     edi, [__boot_pd]
    mov     eax, 0x83                   // PRESENT|WRITE|PS (2 MiB page)
    mov     ecx, 512
.Lpd_fill:
    mov     [edi], eax                  // low dword = phys | flags
    add     eax, 0x200000               // += 2 MiB
    add     edi, 8                      // next 8-byte PD entry
    dec     ecx
    jnz     .Lpd_fill

    // CR4.PAE (bit 5) - required before enabling long-mode paging.
    mov     eax, cr4
    or      eax, (1 << 5)
    mov     cr4, eax

    // CR3 = PML4 physical base.
    lea     eax, [__boot_pml4]
    mov     cr3, eax

    // EFER.LME (IA32_EFER, MSR 0xC000_0080, bit 8).
    mov     ecx, 0xC0000080
    rdmsr
    or      eax, (1 << 8)
    wrmsr

    // CR0.PG (bit 31); PE|ET are already set by PVH. Paging now on.
    mov     eax, cr0
    or      eax, (1 << 31)
    mov     cr0, eax

    // Load the 64-bit GDT and far-RET into the 64-bit code segment (sel 0x08).
    // Loading a CS with L=1 while EFER.LME=1 & CR0.PG=1 activates 64-bit mode.
    lgdt    [__boot_gdt64_ptr]
    push    0x08                        // CS selector
    lea     eax, [.Llong_mode]
    push    eax                         // 32-bit EIP target (< 4 GiB)
    retf

.code64
.Llong_mode:
    // Reload data/stack selectors against our GDT (sel 0x10).
    mov     ax, 0x10
    mov     ss, ax
    mov     ds, ax
    mov     es, ax
    mov     fs, ax
    mov     gs, ax

    lea     rsp, [rip + __boot_stack_top]

    // Clear .bss : [__bss_start, __bss_end). Excludes the page tables/stack.
    lea     rdi, [rip + __bss_start]
    lea     rcx, [rip + __bss_end]
    sub     rcx, rdi
    xor     eax, eax
    rep     stosb

    // hvm_start_info pointer: was in ebx, becomes SysV arg0 (rdi). It is a
    // sub-4 GiB physical address, so `mov edi, ebx` zero-extends correctly.
    mov     edi, ebx

    and     rsp, -16                    // SysV: 16-byte aligned before `call`
    call    rust_main                   // extern "C" fn rust_main(usize) -> !

    // rust_main is `-> !`; belt-and-suspenders halt if it ever returns.
.Lhalt:
    cli
    hlt
    jmp     .Lhalt
"#
);

// ===========================================================================
// MV / tb-boot v0: the SECOND x86_64 entry (the L1 sovereignty rung).
// ===========================================================================
// The project's OWN KVM VMM, `tb-vmm`, boots THIS SAME kernel ELF directly in
// 64-bit long mode via our boot contract — it does NOT use the PVH note and
// does NOT run the A0 32->64 trampoline above. tb-vmm finds the kernel's
// 64-bit entry through the TABOS ELF note (below) and jumps to `_tb_start`
// with paging already on (tb-vmm's identity tables) and `rdi` already holding
// the guest-physical `TbBootInfo*` (SysV arg0). The PVH path (QEMU/Firecracker)
// is untouched: both notes coexist in the PT_NOTE phdr, both entries coexist in
// `.text`, and exactly one of them runs per boot.
//
// Verified sources (the PRE-state tb-vmm establishes before the first KVM_RUN,
// which `_tb_start` relies on — do NOT re-derive these from memory):
//  * Long-mode sregs mirror Firecracker `src/vmm/src/arch/x86_64/regs.rs`
//    (`configure_segments_and_sregs` / `setup_page_tables`, the LinuxBoot arm):
//    CODE = gdt_entry(0xa09b,0,0xfffff) -> L=1 64-bit code; DATA =
//    gdt_entry(0xc093,...); `cr0 |= PE(0x1)|PG(0x8000_0000)`,
//    `cr4 |= PAE(0x20)`, `efer |= LME(0x100)|LMA(0x400)`, `cr3 = PML4`, and
//    PD = 512 * `(i<<21)|0x83` identity-mapping [0,1 GiB) with 2 MiB pages.
//  * Entry register state mirrors `regs.rs::setup_regs`: `rflags = 0x2`,
//    `rip = entry`. Firecracker's *Linux* ABI puts its boot pointer in `rsi`
//    (zero page); OUR tb-boot v0 contract instead puts the `TbBootInfo*` in
//    `rdi` = the first SysV INTEGER argument (System V AMD64 psABI §3.2.3:
//    "the next available register of the sequence %rdi, %rsi, ..."), so the
//    `extern "C" fn rust_main(boot_info)` receives the pointer directly.
//  * tb-boot v0 ABI (crates/tb-boot): TB_NOTE_NAME = "TABOS",
//    TB_NOTE_TYPE_ENTRY64 = 0x5442_0001, desc = u64 = the 64-bit entry addr.
//    Mirrors XEN_ELFNOTE_PHYS32_ENTRY (type 18) but carries a 64-bit entry.
global_asm!(
r#"
// ---------------------------------------------------------------------------
// TABOS ELF note: PT_NOTE name "TABOS", type 0x54420001, desc = u64 _tb_start.
// (a) PRE: KEEP'd into the PT_NOTE phdr (kernel/linker/x86_64.ld). POST: tb-vmm
//     reads `desc` (the kernel's 64-bit entry) and jumps there in long mode.
//     Coexists with the Xen note in the same PT_NOTE segment: QEMU/Firecracker
//     match the Xen note (type 18), tb-vmm matches TABOS (type 0x54420001).
// (b) ABI: System V ELF note, 4-byte aligned (mirrors the Xen note; loaders
//     mis-pad notes at other alignments). Byte layout (consumer view):
//       [ 0.. 4)  n_namesz = 6            (.long)   sizeof("TABOS\0")
//       [ 4.. 8)  n_descsz = 8            (.long)   sizeof(u64 entry)
//       [ 8..12)  n_type   = 0x54420001   (.long)   == TB_NOTE_TYPE_ENTRY64
//       [12..20)  "TABOS\0" + 2 pad bytes (name field, padded to 4)
//       [20..28)  _tb_start as 8-byte LE  (desc field = the 64-bit entry)
// (c) Tested by: the vmm-boot CI job (tb-vmm boots this ELF and reaches
//     "M4: user/ring OK"); offsets cross-checked vs tb-boot's #[cfg(test)].
// ---------------------------------------------------------------------------
.section .note.TABOS, "a", @note
.align 4
.long   6                       // n_namesz = sizeof("TABOS\0")
.long   8                       // n_descsz = sizeof(u64 entry)
.long   0x54420001              // n_type   = TB_NOTE_TYPE_ENTRY64
.asciz  "TABOS"                 // n_name   ("TABOS\0", 6 bytes)
.align  4                       // pad the name field to a 4-byte boundary
.quad   _tb_start               // n_desc   = 64-bit entry address (LE u64)

// ---------------------------------------------------------------------------
// Reserved 64-bit boot stack for the tb-boot path. NOBITS, placed in
// `.boot.stack` so the linker puts it BEFORE __bss_start (no .bss-clear ever
// touches it). Distinct from the PVH __boot_stack: only one entry runs per
// boot, so the duplicate reservation costs nothing in the file (NOBITS).
// ---------------------------------------------------------------------------
.section .boot.stack, "aw", @nobits
.align 16
__tb_boot_stack_bottom: .skip 0x10000      // 64 KiB tb-boot boot stack
__tb_boot_stack_top:

// ===========================================================================
// `_tb_start` (tb-boot v0 64-bit entry). tb-vmm jumps here.
// (a) PRE (tb-boot v0 contract; tb-vmm sets this up before the first KVM_RUN):
//     64-bit long mode, paging ON via tb-vmm's identity tables (CR3 loaded;
//     CR0.PG|PE, CR4.PAE, EFER.LME|LMA set), flat 64-bit CS (L=1) + flat data
//     segments, rdi = guest-physical TbBootInfo* (SysV arg0), rsi = 0,
//     rflags = 0x2 (IF=0, DF=0). POST: rsp on the reserved tb-boot stack
//     (16-aligned), rdi unchanged, then `call rust_main` (rust_main is `-> !`).
//     Deliberately does NOT touch PVH/A0: no GDT/CR3/EFER/CR0 programming and
//     no .bss clear — tb-vmm already established paging, and KVM-mapped guest
//     RAM is zero-filled (so .bss is already zero; clearing it here would risk
//     wiping a boot struct that a loader placed in the image's NOBITS range).
// (b) ABI: System V AMD64. The incoming rdi (INTEGER arg0) is preserved
//     verbatim into rust_main. `cld` honours the psABI "DF clear on entry"
//     rule; rsp is 16-byte aligned before `call` (callee sees rsp%16==8).
// (c) Tested by: the vmm-boot CI job — `_tb_start` must reach the SAME M0-M4
//     markers the PVH path prints, proving identical kernel state.
// ===========================================================================
.section .text._tb_start, "ax", @progbits
.code64
.global _tb_start
_tb_start:
    cli                                 // tb-vmm has no IDT; keep IF masked
    cld                                 // psABI: DF=0 on entry to rust_main

    // Reserved 64-bit boot stack (RIP-relative; small code model, < 4 GiB).
    lea     rsp, [rip + __tb_boot_stack_top]
    and     rsp, -16                    // SysV: 16-byte aligned before `call`

    // rdi already = guest-physical TbBootInfo* (SysV arg0); pass it untouched.
    call    rust_main                   // extern "C" fn rust_main(usize) -> !

    // rust_main is `-> !`; belt-and-suspenders halt if it ever returns.
.Ltb_halt:
    cli
    hlt
    jmp     .Ltb_halt
"#
);

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`,
//! `install_traps`, `breakpoint`) delegates to via `arch::mod`. ALL x86_64
//! `unsafe` and assembly is confined to this `arch::x86_64` subtree
//! (KERNEL-FOUNDATION-SPEC §1); every other crate is `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.
//! MV (the L1 sovereignty rung) adds a SECOND x86_64 entry in `boot`: a TABOS
//! ELF note (PT_NOTE name "TABOS", type 0x54420001, desc = u64 `_tb_start`
//! address) plus the 64-bit `_tb_start` that the project's own `tb-vmm` jumps
//! to directly in long mode — NO PVH note, NO A0 trampoline on that path. Both
//! notes coexist in the PT_NOTE phdr and both entries coexist in `.text`:
//! QEMU/Firecracker use the Xen note, tb-vmm uses TABOS, one runs per boot.
//! M1 adds CPU trap handling: `gdt` installs a permanent flat 64-bit GDT + TSS
//! (IST stacks), `idt` installs the 256-gate IDT, and `trap` holds the entry
//! thunks + the extern "C" handler that dispatches into safe Rust policy.
//! M2 adds the cooperative context switch: `sched` holds the naked
//! `ctx_switch` (saves/restores ONLY the psABI Fig. 3.4 callee-saved set
//! {rbx, rbp, r12-r15} + rsp, callee-saved-on-stack model) and the
//! initial-frame fabricator that tb-hal's shared `Task`/`task_create`/
//! `yield_to` layer builds on.
//! M3 adds the MMU layer: `mmu` holds the privileged paging-register
//! wrappers (read/write CR3, `invlpg`, CR4.PGE toggle, RDMSR/WRMSR for
//! IA32_EFER.NXE) plus the in-HAL `mmu_init`/`mmu_selftest` that splice a
//! new 4 KiB mapping at 0x4000_0000 into the LIVE boot page tables and
//! verify a remap with `invlpg`.
//! M4 adds the user/ring boundary: `user` holds the ring3 entry (`iretq`
//! into a ring3 stub via the DPL3 user GDT descriptors + a valid `TSS.RSP0`),
//! the DPL=3 `int 0x80` IDT gate, the ring0 syscall entry/handler, and the
//! `user_demo` round-trip that maps a `U/S=1` code+stack page through the M3
//! tables, drops to ring3, takes the stub's syscall and returns the verdict.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

// M1 trap stack: GDT/TSS, IDT, and the trap entry/dispatch asm + handler.
pub mod gdt;
pub mod idt;
pub mod trap;

// M2 cooperative switch: naked ctx_switch + new-task stack fabrication.
pub mod sched;

// M3 MMU: privileged paging-register wrappers (CR3, CR4.PGE, INVLPG,
// RDMSR/WRMSR for IA32_EFER.NXE) + the in-HAL 4 KiB map/remap self-test that
// splices a TEST_VA = 0x4000_0000 mapping into the live boot page tables.
pub mod mmu;

// M4 user/ring boundary: DPL3 user GDT descriptors + TSS.RSP0 (gdt.rs), the
// DPL=3 `int 0x80` gate (idt.rs), and HERE the ring3 stub, `iretq`-to-ring3
// entry, ring0 syscall entry/handler, and the `user_demo` round-trip that
// maps a U/S=1 code+stack page and drops to ring3.
pub mod user;

pub use serial::{serial_init, serial_write_byte};

// `breakpoint()` is re-exported as part of tb-hal's public trap surface; the
// `int3` lives in `trap.rs`. `set_trap_hook`/`TrapInfo`/`TrapKind`/`TrapAction`
// and the `dispatch_trap` glue live at the crate root (`lib.rs`).
pub use trap::breakpoint;

// M2: the arch-internal primitives consumed by the shared task layer in
// `lib.rs` (`Task`, `task_create`, `yield_to`). Per-arch contract:
//   * `unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize)`
//     — save the CURRENT task's callee-saved context on its own stack, store
//     the resulting SP to `*prev_sp_save`, adopt `next_sp` and resume the
//     next task (callee-saved-on-stack model, xv6 swtch.S shape).
//   * `fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize`
//     — fabricate a brand-new task's initial frame on `stack` so the FIRST
//     switch into it `ret`s into `entry`; returns the initial saved-SP handle
//     that `task_create` records for the first `yield_to`.
// (Same names + signatures as the aarch64 arm, so `arch/mod.rs` re-exports
// one uniform contract to `lib.rs`.)
pub use sched::{ctx_switch, task_stack_init};

// M3: the safe MMU surface, re-exported through `arch/mod.rs` so `lib.rs` can
// expose `tb_hal::mmu_init` / `tb_hal::mmu_selftest`. `mmu_init` programs
// IA32_EFER.NXE once after `install_traps`; `mmu_selftest` builds, proves and
// remaps the 4 KiB test mapping entirely inside tb-hal, returning pass/fail.
// (Same names + signatures as the aarch64 arm, one uniform contract.)
pub use mmu::{mmu_init, mmu_selftest};

// M4: the safe user/ring surface, re-exported through `arch/mod.rs` so `lib.rs`
// can expose `tb_hal::user_demo`. Drops to ring3, runs the stub's `int 0x80`,
// handles it in ring0 and returns whether the syscall was observed from user
// mode with the expected arg. (Same name + signature as the aarch64 arm.)
pub use user::user_demo;

use core::sync::atomic::{AtomicBool, Ordering};

/// Guards `install_traps()` so the permanent GDT/TSS/IDT are only built once
/// per vCPU even if it is called more than once.
static TRAPS_INSTALLED: AtomicBool = AtomicBool::new(false);

/// Install real CPU exception/interrupt handling: load the permanent GDT+TSS
/// (with IST stacks) FIRST, then the IDT (whose #DF/NMI/#MC gates reference
/// those IST stacks). Idempotent; called once from `rust_main` via
/// `tb_hal::install_traps()`.
pub fn install_traps() {
    if TRAPS_INSTALLED.swap(true, Ordering::SeqCst) {
        return;
    }
    // Order matters: the IDT's IST indices select TSS stacks the GDT installs.
    gdt::init();
    idt::init();
}

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, as the fatal
/// (`TrapAction::Halt`) trap terminator, and as the `#[panic_handler]`
/// fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     its markers; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! TABOS kernel entry shim (M4: user/ring boundary).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust. THIS file is the
//! single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker
//! to expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into),
//! and the `unsafe_code` lint flags it. All real unsafe + assembly is confined
//! to tb-hal (KERNEL-FOUNDATION-SPEC.md §1).
//!
//! M2 (kept verbatim) proves the cooperative context switch: two kernel tasks
//! (A and B) on kernel-owned static stacks voluntarily `yield_to` each other
//! for `ROUND_TRIPS` strict A,B,A,B round-trips. tb-hal switches only the ABI
//! callee-saved registers + SP, so each task carries locals ACROSS every yield
//! as a REGISTER-INTEGRITY CANARY; divergence prints \"M2: FAIL <why>\". On
//! success it prints \"M2: context-switch OK\". The M0 serial hello and the M1
//! breakpoint round-trip are kept verbatim ahead of it.
//!
//! M3 (kept) appends the MMU proof: `mmu_init()`, a serial line proving the
//! UART mapping survived the enable, then `mmu_selftest()` (map -> write ->
//! verify -> remap -> re-verify). DoD marker: \"M3: mmu OK\".
//!
//! M4 (this milestone) appends the user/ring boundary proof. After M3, the
//! kernel calls `tb_hal::user_demo()`: tb-hal sets up USER-accessible code +
//! stack pages (M3 mmu layer + USER permission bits), drops the CPU to
//! unprivileged mode (x86_64 ring 3 / aarch64 EL0) at a tiny user stub, the
//! stub issues ONE syscall (`int 0x80` / `svc #0`) that traps back into the
//! kernel, the safe handler records it (+ its magic arg) and returns the CPU
//! to the kernel. `user_demo()` returns true iff the syscall was observed from
//! user mode with arg == 0xCAFE. DoD marker: \"M4: user/ring OK\". ALL the new
//! unsafe/asm lives in tb-hal; this crate calls one safe fn and branches on a
//! bool.
//!
//! MV (the L1 sovereignty rung) adds a SECOND boot path WITHOUT touching this
//! self-test: the project's own `tb-vmm` boots this SAME kernel ELF directly in
//! 64-bit long mode via tb-boot v0 (tb-hal's `_tb_start` + the TABOS ELF note),
//! with `boot_info` = the guest-physical `tb_boot::TbBootInfo` pointer instead
//! of a PVH `hvm_start_info`. `rust_main` prints "tb-boot: contract v0 OK"
//! first IFF the magic validates (a PVH pointer is silently ignored), then runs
//! M0-M4 identically. The PVH/QEMU regression path is unchanged.

#![no_std]
#![no_main]

use core::hint::black_box;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use tb_hal::{Task, TaskStack, TrapAction, TrapInfo, TrapKind};

/// Ping-pong round-trips (A→B→A counts as one). DoD asks for >= 1000.
const ROUND_TRIPS: usize = 1000;

/// `TURN` value meaning \"task A must run this half-round\".
const TURN_A: usize = 0;
/// `TURN` value meaning \"task B must run this half-round\".
const TURN_B: usize = 1;

/// Initial value of task A's rotating-pattern canary (arbitrary, asymmetric).
const PAT_A_INIT: usize = 0xA5A5_5A5A_DEAD_BEEF;
/// Initial value of task B's rotating-pattern canary (different from A's).
const PAT_B_INIT: usize = 0x0F0F_F0F0_CAFE_F00D;

// --- M2 scheduler bookkeeping (all in THIS forbid-class crate, all safe) ----

/// Task A's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_A: TaskStack<4096> = TaskStack::new();
/// Task B's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_B: TaskStack<4096> = TaskStack::new();

/// Task A's handle as `Task::raw()`, stashed so task B can yield back to A.
static TASK_A_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);
/// Task B's handle as `Task::raw()`, stashed so task A can yield to B.
static TASK_B_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Bootstrap context's handle as `Task::raw()` (slot 0), stashed BEFORE the
/// ping-pong starts so task A can hand the CPU back to `rust_main` after the
/// M2 verdict — M3/M4 then run in the bootstrap context.
static BOOT_TASK_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Set by task A immediately after the M2 success marker and right before it
/// yields back to the bootstrap context. `rust_main` refuses to start M3
/// without it (fail-closed against any stray resume of slot 0).
static M2_PASSED: AtomicBool = AtomicBool::new(false);

/// Whose half-round it is: the strict-alternation flag (TURN_A / TURN_B).
static TURN: AtomicUsize = AtomicUsize::new(TURN_A);

/// Shared increment counter: A sees it == 2*i at round i, B sees == 2*j + 1.
static COUNTER: AtomicUsize = AtomicUsize::new(0);

/// Set by task B after it audited its own canaries on its final round.
static B_VERIFIED: AtomicBool = AtomicBool::new(false);

/// Boot entry. Reached by EITHER of tb-hal's two x86_64 entries (or the
/// aarch64 `_start`); each sets up a stack and places the boot-info pointer in
/// SysV arg0 before calling here:
///   * PVH (`_start`, QEMU/Firecracker): `rdi` = `hvm_start_info` phys addr.
///   * tb-boot v0 (`_tb_start`, the project's `tb-vmm`): `rdi` = guest-physical
///     `tb_boot::TbBootInfo` addr (identity-mapped; magic-validated below).
///   * aarch64 (`_start`): `x0` = FDT blob (MV is an x86_64-first follow-up).
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(boot_info: usize) -> ! {
    // --- M0 proof (kept verbatim): serial first-light ----------------------
    tb_hal::serial_init();

    // --- MV / tb-boot v0: announce the contract IFF tb-vmm booted us -------
    // On the tb-boot path `boot_info` is the guest-physical address of an
    // identity-mapped `tb_boot::TbBootInfo` whose magic validates; on the PVH
    // path it is an `hvm_start_info` pointer whose magic does NOT match, so we
    // silently skip (fail-closed; never misread). tb-hal performs the single
    // guarded raw read of the pointer — this `#![forbid(unsafe_code)]`-class
    // crate only compares the returned magic against `tb_boot::TB_BOOT_MAGIC`.
    // Printing this is OPTIONAL and does NOT gate M0-M4: the PVH regression path
    // skips it and emits the same markers below.
    if tb_hal::read_boot_magic(boot_info) == Some(tb_boot::TB_BOOT_MAGIC) {
        tb_hal::serial_write_str("tb-boot: contract v0 OK\n");
    }

    tb_hal::serial_write_str("hello from rust_main\n");

    // --- M1 proof (kept): install traps, take a breakpoint, resume ---------
    tb_hal::install_traps();
    tb_hal::set_trap_hook(trap_hook);
    tb_hal::serial_write_str("trap-test: triggering breakpoint\n");
    tb_hal::breakpoint(); // int3 (x86_64) / brk #0 (aarch64); hook -> Resume
    tb_hal::serial_write_str("trap-test: resumed past breakpoint\n");
    tb_hal::serial_write_str("M1: traps OK\n");

    // --- M2 proof (kept): cooperative context-switch ping-pong -------------
    tb_hal::serial_write_str("ctx-test: starting ping-pong\n");
    BOOT_TASK_RAW.store(tb_hal::current_task().raw(), Ordering::Release);
    let task_a = tb_hal::task_create(STACK_A.take(), task_a_main);
    let task_b = tb_hal::task_create(STACK_B.take(), task_b_main);
    TASK_A_RAW.store(task_a.raw(), Ordering::Release);
    TASK_B_RAW.store(task_b.raw(), Ordering::Release);
    tb_hal::yield_to(task_a);

    // Fail-closed gate: the ONLY legal way back here is task A's post-verdict
    // hand-off. Anything else (a stray yield to slot 0) is an M2 failure.
    if !M2_PASSED.load(Ordering::Acquire) {
        fail("bootstrap context resumed before the M2 verdict");
    }

    // --- M3: MMU bring-up + map/remap self-test ----------------------------
    tb_hal::serial_write_str("mmu-test: init\n");
    tb_hal::mmu_init();
    tb_hal::serial_write_str("mmu-test: enabled, serial alive\n");
    if tb_hal::mmu_selftest() {
        tb_hal::serial_write_str("M3: mmu OK\n"); // <-- the M3 DoD marker
    } else {
        tb_hal::serial_write_str("M3: FAIL\n");
        tb_hal::halt();
    }

    // --- M4: user/ring boundary -- drop to ring3/EL0, syscall, trap back ----
    // tb-hal maps USER-accessible code + stack pages (M3 mmu layer + USER
    // permission bits), drops the CPU to unprivileged mode at a tiny user
    // stub, the stub issues ONE syscall (int 0x80 / svc #0) that traps back
    // into the kernel, the safe handler records it (+ its magic arg) and the
    // CPU returns here. user_demo() is true iff the syscall was seen from user
    // mode with arg == 0xCAFE. All the new unsafe/asm lives in tb-hal; this
    // forbid(unsafe_code)-class crate only branches on the bool.
    tb_hal::serial_write_str("user-test: entering unprivileged mode\n");
    if tb_hal::user_demo() {
        tb_hal::serial_write_str("M4: user/ring OK\n"); // <-- the M4 DoD marker
    } else {
        tb_hal::serial_write_str("M4: FAIL\n");
    }
    tb_hal::halt()
}

/// Task A (\"ping\"): drives `ROUND_TRIPS` strict A,B,A,B round-trips against
/// task B, renders the M2 verdict, then hands the CPU back to the bootstrap
/// context so `rust_main` can run the M3/M4 sequence.
fn task_a_main() {
    let task_b = Task::from_raw(TASK_B_RAW.load(Ordering::Acquire));

    let mut a_loops: usize = 0; // canary 1: monotonic loop count
    let mut a_sum: usize = 0; // canary 2: accumulator over the index
    let mut a_pat: usize = PAT_A_INIT; // canary 3: rotating bit pattern

    let mut i: usize = 0;
    while i < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: turn flag not A at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * i {
            fail("A: shared counter out of sequence");
        }
        if black_box(a_loops) != i {
            fail("A: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        a_loops = black_box(a_loops) + 1;
        a_sum = black_box(a_sum).wrapping_add(i);
        a_pat = black_box(a_pat).rotate_left(1);
        TURN.store(TURN_B, Ordering::Release);

        tb_hal::yield_to(task_b); // <-- the cooperative switch under test

        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: alternation broken after resume");
        }
        i += 1;
    }

    let mut want_sum: usize = 0;
    let mut want_pat: usize = PAT_A_INIT;
    let mut k: usize = 0;
    while k < ROUND_TRIPS {
        want_sum = black_box(want_sum).wrapping_add(k);
        want_pat = black_box(want_pat).rotate_left(1);
        k += 1;
    }
    if black_box(a_loops) != ROUND_TRIPS {
        fail("A: final loop count wrong");
    }
    if black_box(a_sum) != want_sum {
        fail("A: final sum canary wrong");
    }
    if black_box(a_pat) != want_pat {
        fail("A: final pattern canary wrong");
    }
    if COUNTER.load(Ordering::Acquire) != 2 * ROUND_TRIPS {
        fail("A: final shared counter wrong");
    }
    if !B_VERIFIED.load(Ordering::Acquire) {
        fail("A: task B never reported success");
    }

    tb_hal::serial_write_str("M2: context-switch OK\n"); // <-- the M2 DoD marker

    M2_PASSED.store(true, Ordering::Release);
    tb_hal::yield_to(Task::from_raw(BOOT_TASK_RAW.load(Ordering::Acquire)));

    fail("A: resumed after handing control back to bootstrap")
}

/// Task B (\"pong\"): mirror half of the ping-pong, with its own canary locals
/// live across every yield. Audits its canaries on the FINAL round before the
/// last yield and publishes the verdict via `B_VERIFIED`.
fn task_b_main() {
    let task_a = Task::from_raw(TASK_A_RAW.load(Ordering::Acquire));

    let mut b_loops: usize = 0; // canary 1: monotonic loop count
    let mut b_sum: usize = 0; // canary 2: accumulator over the index
    let mut b_pat: usize = PAT_B_INIT; // canary 3: rotating bit pattern

    let mut j: usize = 0;
    while j < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_B {
            fail("B: turn flag not B at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * j + 1 {
            fail("B: shared counter out of sequence");
        }
        if black_box(b_loops) != j {
            fail("B: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        b_loops = black_box(b_loops) + 1;
        b_sum = black_box(b_sum).wrapping_add(j);
        b_pat = black_box(b_pat).rotate_left(1);
        j += 1;

        if j == ROUND_TRIPS {
            let mut want_sum: usize = 0;
            let mut want_pat: usize = PAT_B_INIT;
            let mut k: usize = 0;
            while k < ROUND_TRIPS {
                want_sum = black_box(want_sum).wrapping_add(k);
                want_pat = black_box(want_pat).rotate_left(1);
                k += 1;
            }
            if black_box(b_loops) != ROUND_TRIPS {
                fail("B: final loop count wrong");
            }
            if black_box(b_sum) != want_sum {
                fail("B: final sum canary wrong");
            }
            if black_box(b_pat) != want_pat {
                fail("B: final pattern canary wrong");
            }
            B_VERIFIED.store(true, Ordering::Release);
        }

        TURN.store(TURN_A, Ordering::Release);
        tb_hal::yield_to(task_a); // <-- the cooperative switch under test
    }

    fail("B: resumed after completing all rounds")
}

/// Emit the M2 failure verdict (\"M2: FAIL <why>\") over serial and park the
/// core. Never returns; the run scripts then miss the later markers.
fn fail(why: &str) -> ! {
    tb_hal::serial_write_str("M2: FAIL ");
    tb_hal::serial_write_str(why);
    tb_hal::serial_write_byte(b'\n');
    tb_hal::halt()
}

/// Safe trap-dispatch policy hook (kept from M1: policy lives in this
/// `forbid(unsafe_code)`-class crate, not in tb-hal's raw entry asm).
fn trap_hook(info: &TrapInfo) -> TrapAction {
    match info.kind {
        TrapKind::Breakpoint => {
            tb_hal::serial_write_str("trap: breakpoint, resuming\n");
            TrapAction::Resume
        }
        _ => {
            tb_hal::serial_write_str("trap: fatal fault, halting\n");
            tb_hal::serial_write_str("  cause=");
            write_hex_u64(info.cause);
            tb_hal::serial_write_str(" fault_addr=");
            write_hex_u64(info.fault_addr);
            tb_hal::serial_write_str(" pc=");
            write_hex_u64(info.pc);
            tb_hal::serial_write_byte(b'\n');
            TrapAction::Halt
        }
    }
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
/// Pure safe Rust (no `core::fmt`, no allocation).
fn write_hex_u64(value: u64) {
    tb_hal::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        tb_hal::serial_write_byte(c);
        shift -= 4;
    }
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str("panic\n");
    tb_hal::halt()
}

//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 serial + M1 traps + M2
//! tasks + M3 MMU + M4 user/ring boundary).
//!
//! Single crate where `unsafe`/asm is allowed (framekernel rule,
//! KERNEL-FOUNDATION-SPEC.md §1). Raw pokes live in `arch/`; THIS file is the
//! thin, mostly-safe facade the `kernel` crate is allowed to call:
//!
//! M0: [`serial_init`], [`serial_write_byte`], [`serial_write_str`], [`halt`].
//! M1: [`install_traps`], [`breakpoint`], [`set_trap_hook`], [`TrapInfo`] /
//!     [`TrapKind`] / [`TrapAction`] (the safe trap-dispatch ABI).
//! M2: [`Task`], [`task_create`], [`yield_to`], [`TaskStack`], [`current_task`]
//!     (cooperative context switch; the saved SP is the whole per-task handle).
//! M3: [`mmu_init`], [`mmu_selftest`] (MMU bring-up + map/remap self-test; the
//!     shared typed table layer is `mmu.rs`).
//! M4 (this milestone): [`user_demo`] — drop the CPU to unprivileged mode
//!     (x86_64 ring 3 / aarch64 EL0) at a tiny user stub, have it issue ONE
//!     syscall (`int 0x80` / `svc #0`) that traps back into the kernel,
//!     observe it (and its magic argument) from the safe handler, and return
//!     the CPU to the kernel. The whole round-trip + all new unsafe/asm lives
//!     in `arch::user`; the kernel crate only branches on the returned bool.
//!
//! POLICY lives in safe Rust: tb-hal's per-arch asm marshals a raw
//! `TrapFrame`, an `extern \"C\"` handler (the ONLY raw-frame deref) builds a
//! safe [`TrapInfo`] and calls the registered hook via [`dispatch_trap`]; the
//! default hook returns [`TrapAction::Halt`].

#![no_std]
#![deny(missing_docs)]

use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

mod arch;
mod mmu; // M3: shared typed page-table layer (PageTable512/Frame4K + entry math).

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: a loop over [`serial_write_byte`]; performs no `unsafe`.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

// ===========================================================================
// M1: trap installation + safe dispatch ABI
// ===========================================================================

/// Install real CPU exception/interrupt handling for the current architecture.
///
/// * x86_64: load a PERMANENT flat 64-bit GDT (null, ring0 code, ring0 data,
///   64-bit TSS, ring3 user code/data), reload `CS`/data segments, `ltr` the
///   TSS, then load a 256-entry IDT of 64-bit interrupt gates. `#DF`/NMI/`#MC`
///   route through TSS IST stacks.
/// * aarch64: point `VBAR_EL1` at the 2 KiB-aligned, 16×128-byte vector table.
///
/// Idempotent. Call once early from `rust_main`, before [`breakpoint`].
pub fn install_traps() {
    arch::install_traps();
}

/// Execute a software breakpoint trap on the current architecture.
///
/// * x86_64: `int3` (`#BP`, vector 3) — a TRAP whose CPU-saved `RIP` already
///   points PAST the instruction, so it resumes automatically on
///   [`TrapAction::Resume`].
/// * aarch64: `brk #0` — a SYNCHRONOUS exception (`ESR_EL1.EC = 0x3C`) whose
///   `ELR_EL1` points AT the instruction; the trap entry advances `ELR_EL1` by
///   4 on [`TrapAction::Resume`].
pub fn breakpoint() {
    arch::breakpoint();
}

/// The architecture-neutral classification of a trap, derived in the per-arch
/// `extern \"C\"` handler from the raw cause (vector + error code on x86_64,
/// `ESR_EL1.EC` on aarch64).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapKind {
    /// Software breakpoint: x86 `#BP` (vector 3) / aarch64 `brk` (EC `0x3C`).
    Breakpoint,
    /// Page / data fault: x86 `#PF` (vector 14) / aarch64 data abort
    /// (EC `0x24`/`0x25`). [`TrapInfo::fault_addr`] holds the faulting address.
    PageFault,
    /// Undefined / invalid instruction: x86 `#UD` (vector 6) / aarch64 Unknown
    /// (EC `0x00`).
    Undefined,
    /// Any other trap not specially classified above.
    Other,
}

/// What the dispatch hook asks tb-hal to do after a trap is handled.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapAction {
    /// Return from the trap entry so execution continues past the trapping
    /// instruction (x86: `iretq`; aarch64: `eret`, advancing `ELR_EL1` by 4 for
    /// the at-instruction synchronous breakpoint).
    Resume,
    /// Do not return; park the vCPU forever. Used for fatal faults and as the
    /// default policy when no hook is registered.
    Halt,
}

/// A safe, fully-owned description of a trap, handed to the dispatch hook.
///
/// Built inside tb-hal's per-arch handler from the raw `TrapFrame`; it borrows
/// nothing from the raw frame, so the hook (in the otherwise-`forbid(unsafe)`
/// kernel crate) can read it freely.
#[derive(Clone, Copy, Debug)]
pub struct TrapInfo {
    /// The architecture-neutral kind of this trap.
    pub kind: TrapKind,
    /// Raw cause word. x86_64: `(vector << 32) | (error_code & 0xFFFF_FFFF)`.
    /// aarch64: the full `ESR_EL1` value (EC = bits `[31:26]`).
    pub cause: u64,
    /// Faulting address for memory faults (x86 `CR2` for `#PF`; aarch64
    /// `FAR_EL1` for a data abort), otherwise `0`.
    pub fault_addr: u64,
    /// The trapping instruction pointer (x86 saved `RIP`; aarch64 `ELR_EL1`).
    pub pc: u64,
}

/// Storage for the registered trap hook: a `fn(&TrapInfo) -> TrapAction`
/// reinterpreted as `usize`. `0` means \"no hook registered → default halt\".
static TRAP_HOOK: AtomicUsize = AtomicUsize::new(0);

/// The default policy when no hook has been registered: always halt.
fn default_trap_hook(_info: &TrapInfo) -> TrapAction {
    TrapAction::Halt
}

/// Register the safe trap-dispatch policy hook.
///
/// A plain `fn(&TrapInfo) -> TrapAction`; it lives in safe Rust (e.g. the
/// kernel crate under `#![forbid(unsafe_code)]`) and decides per-trap whether
/// to [`TrapAction::Resume`] or [`TrapAction::Halt`].
pub fn set_trap_hook(hook: fn(&TrapInfo) -> TrapAction) {
    TRAP_HOOK.store(hook as usize, Ordering::Release);
}

/// Dispatch a trap to the registered hook (or the default halt policy).
///
/// Called by each per-arch `extern \"C\"` handler with a [`TrapInfo`] it built
/// from the raw frame: the safe boundary between the raw-frame deref
/// (per-arch, `unsafe`) and the policy hook (safe).
pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction {
    let raw = TRAP_HOOK.load(Ordering::Acquire);
    if raw == 0 {
        return default_trap_hook(info);
    }
    // SAFETY: `raw` is non-zero, so it was produced by `set_trap_hook` from a
    // valid `fn(&TrapInfo) -> TrapAction` via `hook as usize`. A function
    // pointer and `usize` are pointer-sized; this is the exact inverse cast.
    let hook: fn(&TrapInfo) -> TrapAction =
        unsafe { core::mem::transmute::<usize, fn(&TrapInfo) -> TrapAction>(raw) };
    hook(info)
}

// ===========================================================================
// M2: cooperative tasks + context switch
// ===========================================================================
//
// Saved-context model (callee-saved-on-stack): `yield_to` saves ONLY the
// callee-saved registers of the outgoing task on its own stack and records the
// resulting SP in that task's slot; resuming is \"load saved SP, pop the
// callee-saved set, return\". A single `usize` (the saved SP) is the whole
// per-task context. Caller-saved regs are dead across the call, so unsaved.
//
// Verified ABI facts (do NOT change register sets / frame layouts without
// re-reading): x86-64 SysV psABI §3.2.1 callee-saved = {rbx, rbp, r12..r15}
// (+rsp); §3.2.2 \"(%rsp + 8) is a multiple of 16\" at entry. AAPCS64 §6.1.1
// callee-saved = r19..r29 + SP (r29=FP, r30=LR carries the resume address);
// §6.4.5.1 \"SP mod 16 = 0\". Initial-frame fabrication (OSDev \"Brendan's
// Multi-tasking Tutorial\"): a fake callee-saved frame whose return address /
// LR is the entry, so the FIRST switch \"returns\" into `entry`. No FP/SIMD
// state is switched (both targets are soft-float).

/// Number of task slots tb-hal tracks, INCLUDING slot 0 (the bootstrap context
/// `rust_main` runs on). Eight leaves headroom without a heap.
const MAX_TASKS: usize = 8;

/// Per-slot saved stack pointer — the WHOLE saved context of a suspended task.
/// `0` means \"no saved context\". `AtomicUsize` for safe interior mutability
/// (single-core cooperative, not racing).
static TASK_SP: [AtomicUsize; MAX_TASKS] = [const { AtomicUsize::new(0) }; MAX_TASKS];

/// Slot index of the task currently executing on this (single) core.
static CURRENT_TASK: AtomicUsize = AtomicUsize::new(0);

/// Next free slot in [`TASK_SP`]; slot 0 is the bootstrap context.
static NEXT_TASK_SLOT: AtomicUsize = AtomicUsize::new(1);

/// Smallest stack [`task_create`] accepts, in `usize` words.
const MIN_STACK_WORDS: usize = 64;

/// An opaque handle to a cooperative kernel task: the slot index into tb-hal's
/// internal saved-SP table. `Copy`; convertible to/from a raw `usize` (see
/// [`Task::raw`]) so the `forbid(unsafe_code)` kernel can stash handles in
/// `AtomicUsize` statics.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Task(usize);

impl Task {
    /// The raw slot index of this handle, for stashing in an `AtomicUsize`.
    pub fn raw(self) -> usize {
        self.0
    }

    /// Rebuild a handle from a value previously obtained via [`Task::raw`].
    ///
    /// Safe: an invalid index cannot cause memory unsafety — it is rejected
    /// fail-closed by [`yield_to`] (bounds + saved-context check).
    pub fn from_raw(raw: usize) -> Self {
        Task(raw)
    }
}

/// Handle of the task currently executing (slot 0 — the bootstrap context —
/// until the first [`yield_to`] after [`task_create`]).
pub fn current_task() -> Task {
    Task(CURRENT_TASK.load(Ordering::Relaxed))
}

/// Fail-closed termination for misuse of the M2 task API: report over serial
/// (best-effort) and park the core. Never returns.
fn task_api_fatal(msg: &str) -> ! {
    serial_write_str("tb-hal: task: ");
    serial_write_str(msg);
    serial_write_byte(b'\n');
    halt()
}

/// Create a cooperative task that starts executing `entry` the first time
/// somebody [`yield_to`]s it.
///
/// `stack` is caller-provided `'static` memory (see [`TaskStack`]; tb-hal does
/// NOT allocate). The arch backend fabricates the INITIAL context frame at the
/// 16-byte-aligned-down top of `stack` so the first switch \"returns\" into
/// `entry` with an ABI-conformant stack.
///
/// `entry` must never return. Fatal (reports + halts) if the stack is too
/// small or all task slots are used.
pub fn task_create(stack: &'static mut [usize], entry: fn()) -> Task {
    if stack.len() < MIN_STACK_WORDS {
        task_api_fatal("task_create: stack too small");
    }
    let slot = NEXT_TASK_SLOT.fetch_add(1, Ordering::Relaxed);
    if slot >= MAX_TASKS {
        task_api_fatal("task_create: too many tasks");
    }
    let sp = arch::task_stack_init(stack, entry);
    TASK_SP[slot].store(sp, Ordering::Release);
    Task(slot)
}

/// Cooperatively switch from the current context to `next`.
///
/// Saves the callee-saved registers + SP of the CURRENT task (on its own
/// stack), records the resulting SP, then loads `next`'s saved SP, restores
/// its callee-saved registers and returns into it. Yielding to the current
/// task is a no-op; an invalid handle is fatal (report + halt).
pub fn yield_to(next: Task) {
    if next.0 >= MAX_TASKS {
        task_api_fatal("yield_to: invalid task handle");
    }
    let prev = CURRENT_TASK.load(Ordering::Relaxed);
    if prev == next.0 {
        return; // self-yield: nothing to switch
    }
    let next_sp = TASK_SP[next.0].load(Ordering::Acquire);
    if next_sp == 0 {
        task_api_fatal("yield_to: target has no saved context");
    }
    CURRENT_TASK.store(next.0, Ordering::Relaxed);
    // SAFETY: `next_sp` was produced by `arch::task_stack_init` (fabricated
    // frame) or a previous `ctx_switch` save; both leave a well-formed
    // callee-saved frame at that SP. `TASK_SP[prev].as_ptr()` is a valid
    // 'static atomic for the single word `ctx_switch` stores. Single core +
    // cooperative: no other context can touch either slot mid-switch.
    unsafe { arch::ctx_switch(TASK_SP[prev].as_ptr(), next_sp) }
}

/// A statically-allocatable, 16-byte-aligned kernel task stack of `WORDS`
/// `usize` words, takeable exactly once as `&'static mut [usize]`.
///
/// Lets the `#![forbid(unsafe_code)]` kernel OWN its static stack arrays and
/// still mint the unique `&'static mut` [`task_create`] requires. The atomic
/// one-shot gate makes aliased handouts impossible; a second [`TaskStack::take`]
/// is fatal.
#[repr(C, align(16))]
pub struct TaskStack<const WORDS: usize> {
    mem: UnsafeCell<[usize; WORDS]>,
    taken: AtomicBool,
}

// SAFETY: the ONLY route to the inner array is `take()`, whose swap-once gate
// hands out at most one `&'static mut` ever, so shared references to the cell
// never alias the interior data.
unsafe impl<const WORDS: usize> Sync for TaskStack<WORDS> {}

impl<const WORDS: usize> TaskStack<WORDS> {
    /// A new zeroed stack; `const`, so it can initialise a kernel `static`.
    pub const fn new() -> Self {
        TaskStack {
            mem: UnsafeCell::new([0; WORDS]),
            taken: AtomicBool::new(false),
        }
    }

    /// Hand out the stack as `&'static mut [usize]` — exactly once. A second
    /// call on the same static is fatal (fail-closed).
    pub fn take(&'static self) -> &'static mut [usize] {
        if self.taken.swap(true, Ordering::AcqRel) {
            task_api_fatal("TaskStack::take: taken twice");
        }
        // SAFETY: the swap guarantees this runs at most once per static, so the
        // `&mut` minted here is unique for `'static`; `UnsafeCell` makes
        // mutating the interior of an immutable `static` well-defined.
        let array: &'static mut [usize; WORDS] = unsafe { &mut *self.mem.get() };
        &mut array[..]
    }
}

// ===========================================================================
// M3: MMU bring-up + map/remap self-test
// ===========================================================================
//
// The typed table layer both backends share is `mmu.rs` (pure safe Rust); ALL
// new unsafe + asm (CR3/EFER/invlpg, MAIR/TCR/TTBR0/SCTLR, dsb/isb/tlbi, the
// mapped-VA derefs) lives in `arch/`. The kernel only sees the two safe fns.

/// Bring the MMU to the M3 baseline. Call ONCE from `rust_main`, AFTER
/// [`install_traps`] (a broken mapping then reports via the trap path instead
/// of an opaque hang / triple fault).
///
/// * x86_64: paging is already LIVE; this programs `EFER.NXE` so PTE bit 63
///   (NX) is honoured. `IA32_PAT` keeps its power-on default.
/// * aarch64: brings the MMU up from cold — identity tables (L1[0] Device for
///   the PL011 gigabyte, L1[1] Normal-WB for RAM, AF on every leaf), then
///   `MAIR_EL1`/`TCR_EL1`/`TTBR0_EL1` → `isb` → `SCTLR_EL1.{M,C,I}` → `isb`.
pub fn mmu_init() {
    arch::mmu_init();
}

/// Run the in-HAL MMU map/remap self-test; `true` = pass.
///
/// Maps `TEST_VA` (x86_64 `0x4000_0000` / aarch64 `0x8000_0000`, both OUTSIDE
/// the identity region) to frame A, writes a magic through `TEST_VA`, verifies
/// via frame A's identity address, remaps to frame B (x86: PTE rewrite +
/// `invlpg`; aarch64: full Break-Before-Make + `tlbi`), and verifies the read
/// through `TEST_VA` now sees frame B. Tables/frames are static, 4096-aligned,
/// `.bss`-resident; every raw deref stays in tb-hal's arch backends.
pub fn mmu_selftest() -> bool {
    arch::mmu_selftest()
}

// ===========================================================================
// M4: user/ring boundary (this milestone)
// ===========================================================================
//
// The privileged/unprivileged split end-to-end: tb-hal drops the CPU to ring 3
// (x86_64) / EL0 (aarch64), runs a tiny user stub, the stub issues ONE syscall
// that traps back into the kernel, the safe handler records it, and the CPU
// returns to the kernel. ALL new unsafe/asm lives in `arch::user`; this facade
// just forwards. The kernel crate stays `#![forbid(unsafe_code)]`.

/// M4 user/ring round-trip; `true` = the syscall was observed from user mode
/// with the expected magic argument (`0xCAFE`).
///
/// tb-hal sets up a user-accessible code page + user stack page (via the M3
/// `mmu` machinery, with USER permission bits at every level of the walk),
/// drops the CPU to unprivileged mode at the stub, the stub issues the syscall
/// (x86_64 `int 0x80` with `rax = 0xCAFE`; aarch64 `svc #0` with
/// `x0 = 0xCAFE`), the kernel-side handler records the argument and switches
/// the CPU back into a kernel continuation, and `user_demo` reads the recorded
/// flag/argument. The whole round-trip — USER mappings, the privileged drop
/// (`iretq` / `eret`), the user stub, the syscall entry and the kernel return
/// — lives in `arch::user`; all the new unsafe + assembly is confined there.
pub fn user_demo() -> bool {
    arch::user_demo()
}

// ===========================================================================
// MV: tb-boot v0 — recognise a `tb-vmm` boot (the L1 sovereignty rung)
// ===========================================================================
//
// On the tb-boot path the kernel's `rust_main(boot_info: usize)` is entered
// (via `arch::x86_64::boot::_tb_start`) with `boot_info` = the guest-physical
// address of an identity-mapped `tb_boot::TbBootInfo`. On the PVH path the same
// argument is an `hvm_start_info` pointer instead. The kernel crate is
// `#![forbid(unsafe_code)]`, so it cannot dereference the raw address itself;
// THIS is the single, guarded raw read that lets it tell the two boot paths
// apart by magic — the one place the boundary is crossed, confined to tb-hal.

/// Read the 8-byte `tb-boot` magic at the boot-info pointer, if that pointer is
/// safe to dereference; `None` otherwise (so the caller fail-closed-ignores it).
///
/// `boot_info` is the raw `usize` `rust_main` was entered with. The magic is the
/// first field (offset 0) of `#[repr(C)] tb_boot::TbBootInfo`, so this reads it
/// WITHOUT importing the struct layout. The caller — the `forbid(unsafe_code)`
/// kernel — compares the result against `tb_boot::TB_BOOT_MAGIC`: a match means
/// `tb-vmm` booted us via tb-boot v0; a mismatch (e.g. a PVH `hvm_start_info`
/// pointer, whose magic is `0x336e_c578`) is simply ignored, never misread.
///
/// The read is guarded to the architecture's identity-mapped low window
/// (`[0x1000, 1 GiB)` on x86_64 — the PVH `_start` / tb-vmm 2 MiB-page identity
/// region, which is present and readable) and to 8-byte alignment, so a stray
/// or out-of-window pointer can never fault the boot path; it just yields
/// `None`. aarch64 is an MV follow-up: there the FDT pointer (QEMU `virt` places
/// it at `0x4000_0000`) falls outside this window and is correctly ignored.
pub fn read_boot_magic(boot_info: usize) -> Option<u64> {
    // Lowest address we will touch (reject the null page) and the first address
    // past the identity-mapped window. Both x86_64 boot paths map [0, 1 GiB)
    // with 2 MiB pages: PVH `_start` builds __boot_pd; tb-vmm builds the same
    // shape (Firecracker `regs.rs::setup_page_tables`). Anything in range is
    // present, so an 8-byte read there cannot page-fault.
    const WINDOW_LO: usize = 0x1000;
    const WINDOW_HI: usize = 0x4000_0000; // 1 GiB, exclusive upper bound

    if boot_info < WINDOW_LO {
        return None;
    }
    // Ensure the whole 8-byte read stays inside the window.
    if boot_info > WINDOW_HI - core::mem::size_of::<u64>() {
        return None;
    }
    // A `u64` read must be 8-byte aligned (TbBootInfo is `#[repr(C)]` with
    // `magic: u64` first, so the struct — and thus its magic — is 8-aligned).
    if boot_info % core::mem::align_of::<u64>() != 0 {
        return None;
    }

    // SAFETY: `boot_info` is in [0x1000, 1 GiB - 8] and 8-byte aligned (checked
    // above), so it lies inside the present, identity-mapped 2 MiB-page region
    // the active boot path established (PVH `_start` or tb-vmm), making this
    // 8-byte read both mapped and aligned. `u64` has no invalid bit patterns,
    // so whatever bytes are there form a valid value (we never act on it unless
    // it equals `TB_BOOT_MAGIC`). `read_volatile` stops the optimiser from
    // making assumptions about this foreign, single-producer boot word. The
    // pointee is boot RAM that outlives this call.
    let magic = unsafe { (boot_info as *const u64).read_volatile() };
    Some(magic)
}

/* tb-hal x86_64 linker script - PVH ELF image, loaded at 1 MiB.
 *
 * Boot contract (verified): the image is an ELF that QEMU (-kernel) and
 * Firecracker boot via the Xen "x86/HVM direct boot ABI" (PVH). Selection is
 * driven SOLELY by the XEN_ELFNOTE_PHYS32_ENTRY note (type 18, name "Xen"),
 * which MUST live in a PT_NOTE program header.
 *   Sources: https://xenbits.xen.org/docs/unstable/misc/pvh.html
 *            xen/include/public/elfnote.h  ("notes ... live in a PT_NOTE
 *            segment and have \"Xen\" in the name field"; PHYS32_ENTRY == 18)
 *
 * Load address = 1 MiB (0x0010_0000) == Firecracker HIMEM_START. ET_EXEC,
 * vaddr == paddr (no AT()), so the PVH loader copies each PT_LOAD to p_paddr
 * and the 32-bit entry runs identity-addressed with paging off.
 */

ENTRY(_start)
OUTPUT_FORMAT(elf64-x86-64)
OUTPUT_ARCH(i386:x86-64)

PHDRS
{
    note PT_NOTE FLAGS(4);          /* R   : the Xen PHYS32_ENTRY note        */
    text PT_LOAD FLAGS(5);          /* R E : .note.Xen, .text, .rodata        */
    data PT_LOAD FLAGS(6);          /* R W : .data, .bss (page tables, stack) */
}

SECTIONS
{
    . = 1M;                          /* 0x0010_0000 */
    __image_start = .;

    /* The note is file-backed (in the text PT_LOAD) AND exposed via PT_NOTE.
     * KEEP() protects it from --gc-sections. 4-byte aligned: some loaders
     * (QEMU) mis-calculate note padding when alignment != 4. */
    .note.Xen : ALIGN(4) {
        KEEP(*(.note.Xen))
    } :text :note

    /* MV / tb-boot v0: the TABOS note (PT_NOTE name "TABOS", type 0x54420001,
     * desc = u64 _tb_start) sits in the SAME PT_NOTE segment, right after the
     * Xen note. tb-vmm iterates PT_NOTE and matches type 0x54420001 to find the
     * kernel's 64-bit entry; QEMU/Firecracker match the Xen note (type 18) and
     * ignore this one. KEEP() also anchors `_tb_start` against --gc-sections:
     * the note's `.quad _tb_start` desc is the ONLY reference to that entry.
     * Source: tb-boot v0 ABI (crates/tb-boot); mirrors XEN_ELFNOTE_PHYS32_ENTRY. */
    .note.TABOS : ALIGN(4) {
        KEEP(*(.note.TABOS))
    } :text :note

    .text : ALIGN(16) {
        *(.text._start)
        *(.text .text.*)
    } :text

    .rodata : ALIGN(16) {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    } :text

    . = ALIGN(4096);
    .data : ALIGN(16) {
        *(.data .data.*)
        *(.sdata .sdata.*)
        *(.got) *(.got.plt)
    } :data

    /* NOBITS. The boot page tables (CR3 root) and the boot stack are placed
     * FIRST, OUTSIDE the [__bss_start, __bss_end) window, so the _start
     * .bss-clear can never zero the page tables we are actively running on.
     * Guest RAM is zero at VM start, and _start additionally zeroes the
     * three table pages before use. */
    .bss (NOLOAD) : ALIGN(4096) {
        *(.boot.pagetables)
        *(.boot.stack)
        __bss_start = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        *(COMMON)
        __bss_end = .;
    } :data

    . = ALIGN(4096);
    __image_end = .;

    /DISCARD/ : {
        *(.eh_frame) *(.eh_frame_hdr)
        *(.note.gnu.*) *(.comment)
        *(.dynamic) *(.dynsym) *(.dynstr) *(.hash) *(.gnu.hash)
        *(.interp) *(.rela .rela.*)
    }
}
